const EXAMENES_2022 = [
{ex:"2022-A", n:1, area:"PED", tema:"Convulsión febril compleja", q:"Lactante de 10 meses, es traído a emergencia por presentar movimientos tónico-clónicos generalizados de 20 minutos de duración, que cedió espontáneamente, madre niega convulsión previa. Examen: T° 39°C, FC 128X', FR 24X', SatO2 94%, se evidencia convulsión focalizada de miembro superior derecho que cede con diazepam. ¿Cuál es el diagnóstico probable?", o:["Síndrome de West","Mioclonías","Convulsión febril compleja","Convulsión febril simple","Epilepsia"], c:2, e:"La duración >15 minutos y la focalidad (miembro superior derecho) son criterios de convulsión febril compleja; la simple es generalizada, <15 min y única en 24 h."},
{ex:"2022-A", n:2, area:"CIR", tema:"Cefalea post punción dural", q:"Mujer de 30 años, intervenida de hernioplastia umbilical; habiendo recibido anestesia epidural, 3 horas después presenta cefalea intensa con mareos e hipotensión. ¿Cuál es el diagnóstico probable?", o:["Depresión respiratoria","Schok anafiláctico","Desgarro de duramadre","Reacción vagal","Síndrome de la \"cola de caballo\""], c:2, e:"La punción dural accidental durante la técnica epidural produce fuga de LCR y cefalea postural característica, con mareos e hipotensión; no hay clínica de anafilaxia ni de compresión radicular."},
{ex:"2022-A", n:3, area:"PED", tema:"Pediculosis capitis", q:"Niña de 3 años, con prurito intenso en cuero cabelludo que ha ocasionado lesiones por el rascado. Madre refiere que otras niñas en el nido presentan la misma molestia. Examen: T° 36.5°C, FC 100X', FR 22X', Peso 15 Kg; lesiones papulares eritematosas en cuero cabelludo y pabellones auriculares; linfadenopatías cervicales y occipitales. ¿Cuál es el tratamiento específico?", o:["Malation al 0,5%","Tacrolimus","Ivermectina","Lindano loción","Vaselina"], c:0, e:"El contagio entre niñas del mismo nido con prurito de cuero cabelludo es típico de pediculosis; el malatión al 0.5% es pediculicida específico y eficaz. El lindano se evita en niños por su neurotoxicidad."},
{ex:"2022-A", n:4, area:"MED", tema:"Tiroiditis de De Quervain", q:"¿Con qué agente etiológico está relacionada la tiroiditis de De Quervain?", o:["Infecciones por estafilococo","Radiación","Histoplasmosis","Equinococosis","Virus de la parotiditis"], c:4, e:"La tiroiditis subaguda de De Quervain se asocia clásicamente a infecciones virales previas (parotiditis, coxsackievirus, adenovirus), con tiroides dolorosa tras un cuadro catarral."},
{ex:"2022-A", n:5, area:"CB", tema:"Síndrome de Alport", q:"En un paciente con diagnóstico de Síndrome de Alport (glomerulonefritis hereditaria). Histológicamente. ¿Qué estructura se espera encontrar alterada?", o:["Membrana basal glomerular","Conductos papilares","Túbulos conectores","Conductos colectores corticales","Endotelio de los capilares glomerulares"], c:0, e:"El Alport es un trastorno del colágeno tipo IV que altera la membrana basal glomerular, visible en microscopía electrónica como adelgazamiento y laminación irregular."},
{ex:"2022-A", n:6, area:"MED", tema:"Taponamiento cardiaco", q:"Varón de 60 años, hace una semana presentó fiebre que mejoró con sintomáticos; hace 6 horas presenta dolor torácico y disnea. Examen: sudoroso, pálido, en ortopnea; FR 28X´, FC 100X´, PA 90/50 mmHg; pulso paradógico. ¿Cuál es el diagnóstico más probable?", o:["Taponamiento cardiaco","Neumonía atípica","Aneurisma de aorta torácico","Miocardiopatía dilatada","Cardiopatía isquémica crónica"], c:0, e:"Antecedente viral, hipotensión y pulso paradójico son sugestivos de pericarditis con derrame que evoluciona a taponamiento cardiaco."},
{ex:"2022-A", n:7, area:"CIR", tema:"Lesión articular de rodilla", q:"Varón de 25 años, que todos los fines de semana practica deporte, manifiesta dolor en rodilla derecha que aumenta a la deambulación y provoca leve limitación funcional. ¿Cuál es el examen que permite confirmar el daño articular?", o:["Tomografía axial computarizada","Radiografía comparativa de ambas rodillas","Ecografía de partes blandas","Densitometría ósea","Artroscopía"], c:4, e:"La artroscopía es el método diagnóstico (y terapéutico) definitivo para confirmar lesiones intraarticulares como las meniscales o ligamentarias, superior a la imagen no invasiva."},
{ex:"2022-A", n:8, area:"PED", tema:"Conjuntivitis neonatal por Chlamydia", q:"Neonato de 20 días, nacido de parto vaginal domiciliario, producto de tercera gestación, presenta secreción ocular bilateral. Examen: edema palpebral, quemosis, exudado purulento, discreta opacidad corneal. ¿Cuál es el agente causal más probable?", o:["Chlamydia trachomatis","Staphiloccocus aureus","Haemophilus influenzae","Neisseria gonorrhoeae","Pseudomona aeruginosa"], c:0, e:"La conjuntivitis neonatal por Chlamydia se presenta típicamente entre el 5.º y 14.º día de vida (más tardía que la gonocócica, que aparece en las primeras 48-72 h)."},
{ex:"2022-A", n:9, area:"MED", tema:"Insuficiencia suprarrenal", q:"En un caso de insuficiencia suprarrenal. ¿Qué hallazgo de laboratorio esperaría encontrar?", o:["Hiponatremia","Alcalosis metabólica","Hipocalcemia","Hipokalemia","Hiperglicemia"], c:0, e:"El déficit de mineralocorticoides y glucocorticoides en la insuficiencia suprarrenal primaria causa hiponatremia, hiperkalemia, acidosis e hipoglicemia."},
{ex:"2022-A", n:10, area:"PED", tema:"Reanimación neonatal", q:"¿Qué FiO2 se recomienda en ventilación asistida coordinada con masaje cardiaco durante la reanimación neonatal?", o:["21%","100%","80%","40%","50%"], c:1, e:"Cuando se requiere masaje cardiaco durante la reanimación neonatal, se recomienda incrementar la FiO2 a 100% hasta la recuperación de la frecuencia cardiaca."},
{ex:"2022-A", n:11, area:"GIN", tema:"Embarazo ectópico roto", q:"Paciente de 22 años, ingresa a emergencia por pérdida de conciencia. Examen: PA 70/40 mmHg, FC 100X'; pálida; abdomen doloroso, rebote dudoso; TV: cérvix ligeramente blando móvil, doloroso, útero y anexos difíciles de precisar por dolor. ECO transvaginal: líquido en fondo de saco en regular cantidad. ¿Cuál es el diagnóstico más probable?", o:["Aborto incompleto","Enfermedad pélvica inflamatoria","Embarazo ectópico complicado","Obstrucción abdominal","Apendicitis"], c:2, e:"Hipotensión, dolor pélvico y líquido libre en fondo de saco en mujer en edad fértil orientan a embarazo ectópico roto (complicado) hasta demostrar lo contrario."},
{ex:"2022-A", n:12, area:"PED", tema:"Artritis séptica de rodilla", q:"Escolar de 12 años, presenta hace 6 días dolor en rodilla derecha con sensación de alza térmica e incapacidad funcional para caminar. Examen: PA 110/60 mmHg, FC 100X', T° 38.5°C; rodilla aumentada de volumen con flogosis y dolor para caminar. ¿Cuál es la conducta inmediata a seguir?", o:["Rx.de rodilla","Resonancia","Tomografía","Aspiración articular","Artrotomía"], c:3, e:"Ante sospecha de artritis séptica, la artrocentesis (aspiración articular) es la conducta inmediata para confirmar el diagnóstico mediante análisis del líquido sinovial y guiar el tratamiento."},
{ex:"2022-A", n:13, area:"PED", tema:"Tricocefalosis (prolapso rectal)", q:"Pre escolar de 4 años, es evaluado para riesgo quirúrgico para colonoscopía por prolapso rectal y hematoquecia. Laboratorio: eosinofilia y anemia severa. ¿En qué parásito sospecha?", o:["Trichocephalus dispar","Giardia lamblia","Strongyloides stercoralis","Ascaris lumbricoides","Ancylostoma duodenale"], c:0, e:"La infección masiva por Trichuris trichiura (Trichocephalus dispar) es la causa clásica de prolapso rectal, hematoquecia, eosinofilia y anemia en niños."},
{ex:"2022-A", n:14, area:"MED", tema:"Malaria", q:"Turista de 28 años que procede de selva alta; acude por presentar hace 15 días cefalea, fiebre matutina interdiaria precedida de escalofríos con diaforesis profusa. Examen: ictericia de escleras, matidez en espacio de Traube. ¿Cuál es el diagnóstico más probable?", o:["Malaria","Fiebre amarilla","Zika","Chikungunya","Dengue"], c:0, e:"La fiebre intermitente (terciana) precedida de escalofríos, con ictericia y esplenomegalia (matidez de Traube) en procedencia de zona endémica, es clásica de malaria."},
{ex:"2022-A", n:15, area:"PED", tema:"Reanimación neonatal (meconio)", q:"Recién nacido de 35 semanas, con peso de 2,500 g que nace bañado con líquido amniótico con meconio, es colocado sobre la madre, está hipotónico en apnea. ¿Cuál es la primera acción a realizar?", o:["Aspirar secreciones por boca y nariz","Administrar oxígeno a presión positiva","Colocarlo en ventilación mecánica","Fricción suave con paños tibios y colocarlo sobre uno seco","Administrar oxígeno a flujo libre"], c:3, e:"Según las guías actuales de reanimación neonatal, independientemente de la presencia de meconio, los primeros pasos son calentar, secar y estimular; solo si persiste apnea se pasa a ventilación a presión positiva."},
{ex:"2022-A", n:16, area:"MED", tema:"Cáncer de tiroides diferenciado", q:"¿Cuál es el examen que más se utiliza en la detección y tratamiento de pacientes con cánceres tiroideos diferenciados con enfermedad metastásica, donde la imagen proporciona información no sólo de la glándula sino también de la distribución de la actividad funcional?", o:["Tomografía con emisión de positrones","Tomografía sin contraste","Ecografía tiroidea","Gammagrafía con yodo-131","Resonancia magnética"], c:3, e:"La gammagrafía con yodo-131 permite detectar y tratar (ablación) metástasis de cáncer tiroideo diferenciado, ya que estas células conservan la capacidad de captar yodo."},
{ex:"2022-A", n:17, area:"CIR", tema:"Síndrome compartimental", q:"Varón de 43 años, atendido en emergencia por accidente de tránsito de hace 1 hora. Examen: PA 140/70 mmHg, FC 85X'; pierna izquierda: aumento de volumen y dolor a la movilización; piel lustrosa y tensa; no se palpa pulso pedio. Se evidencia incremento en la presión tisular del miembro. ¿Cuál es el tratamiento indicado?", o:["Yeso muslo pedio","Miotomía anterior","Osteotomía de tibia","Fijación externa","Fasciotomía"], c:4, e:"El aumento de la presión tisular con dolor desproporcionado y ausencia de pulso configura un síndrome compartimental; la fasciotomía urgente es el tratamiento de elección para evitar necrosis muscular."},
{ex:"2022-A", n:18, area:"MED", tema:"Trombosis del seno cavernoso", q:"Mujer de 42 años obesa, portadora de celulitis orbitaria que en forma brusca presenta fiebre, edema de órbita, quemosis, dolor orbitario intenso con oftalmoplejía. ¿Cuál es el diagnóstico más probable?", o:["Meningioma","Aneurisma de la arteria carótida","Carcinoma nasofaríngeo","Fístula carótida-cavernosa","Trombosis del seno cavernoso"], c:4, e:"La celulitis orbitaria complicada con oftalmoplejía y quemosis brusca sugiere extensión a trombosis del seno cavernoso, urgencia con alta mortalidad si no se trata precozmente."},
{ex:"2022-A", n:19, area:"GIN", tema:"COVID-19 en la gestante", q:"Madre gestante a término en inicio de trabajo de parto, con cuadro respiratorio alto con PCR positivo a Sars Cov-2. ¿Cuál es la medida a tomar para evitar el riesgo de contagio al neonato?", o:["Uso de mascarilla adecuada permanente","No lactancia materna","Separación inmediata del niño","Clampaje inmediato del cordón","Cesárea"], c:0, e:"Las guías vigentes recomiendan mantener contacto piel a piel y lactancia materna con uso permanente de mascarilla e higiene de manos, sin requerir separación del binomio ni cesárea por el solo diagnóstico de COVID-19."},
{ex:"2022-A", n:20, area:"MED", tema:"Trastorno esquizoide de personalidad", q:"Contador de 45 años, con trabajo estable; durante el confinamiento por COVID-19 realizó trabajo remoto sin quejas; no ha tenido pareja ni la ha buscado; antes y después del confinamiento se encerraba en su oficina y no compartía actividades sociales con colegas o compañeros. Su facies es inexpresiva, no manifiesta emociones y es parco al hablar. Prefiere las diversiones que puede realizar en solitario. ¿Cuál es el trastorno de personalidad más probable?", o:["Ansiosa","Narcisista","Paranoide","Evitativa","Esquizoide"], c:4, e:"El desinterés genuino por las relaciones (no busca pareja), la expresión emocional restringida y la preferencia por actividades solitarias son propias del trastorno esquizoide, a diferencia del evitativo que sí desea vínculos pero los evita por temor al rechazo."},
{ex:"2022-A", n:21, area:"SP", tema:"Gestión de calidad en salud", q:"¿Cuál es una característica del gerenciamiento de la calidad en salud pública que tiene que ver con la implementación de políticas y estrategias ante la contingencia o proximidad de un daño ambiental y/o social?", o:["Promoción de la salud","Eficiencia","Reducción de riesgo","Equidad","Efectividad"], c:2, e:"Actuar ante la contingencia o proximidad de un daño ambiental o social corresponde al principio de reducción de riesgo dentro de la gestión de calidad en salud pública."},
{ex:"2022-A", n:22, area:"PED", tema:"Síndrome urémico hemolítico", q:"Varón de 3 años, traído a emergencia por irritabilidad y palidez marcada; 4 días antes presentó fiebre, vómitos, dolor abdominal y diarreas sanguinolentas, que se autolimitaron. Examen: FC 120X', FR 25X', T° 37°C, PA 120/90 mmHg; pálido con debilidad marcada y letargia; lesiones equimóticas y petequias en extremidades. Laboratorio: Hb 8.7g/dl, plaquetas 30000/µl, creatinina 1.2 mg/dl; examen de orina: hematíes 50-100/campo. ¿En qué diagnóstico sospecha?", o:["Trombocitopenia inmune primaria","Lupus eritematoso sistémico","Síndrome urémico-hemolítico","Vasculitis","Insuficiencia renal aguda"], c:2, e:"La tríada de anemia hemolítica, trombocitopenia e injuria renal tras un episodio de diarrea sanguinolenta (típicamente por E. coli productor de toxina Shiga) es diagnóstica de síndrome urémico hemolítico."},
{ex:"2022-A", n:23, area:"PED", tema:"Sepsis en cardiopatía congénita cianótica", q:"Niño de 6 años con cardiopatía cianótica congénita, presenta fiebre de 39°C desde hace 7 días, vómitos, cefalea y tos con movilización de secreciones. Examen: FC 100X', FR 25X', SatO2 75%, T° 38°C; cianosis generalizada; subcrepitantes difusos; RC por fuera de línea medio clavicular, hepato esplenomegalia. Laboratorio: leucocitos 22000/µl, segmentados 60%, Hb 17 g/dl, PCR 5 mg/dl, plaquetas 50000/µl. Luego de tomar muestras (3) para cultivo. ¿Cuál es la acción terapéutica inmediata?", o:["Realizar sangría roja","Transfundir plaquetas","Iniciar antibióticos parenterales","Administrar aporte de oxígeno","Observar hasta resultados de cultivos"], c:2, e:"En cardiopatía cianótica con fiebre prolongada y datos de sepsis/probable endocarditis, tras extraer los hemocultivos se debe iniciar antibioticoterapia empírica parenteral sin demora."},
{ex:"2022-A", n:24, area:"MED", tema:"Leucemia linfática crónica", q:"Varón de 76 años, consulta por fatiga y malestar general desde hace 5 meses. Examen: palidez de piel y mucosas, se palpan adenopatías pequeñas en cuello y axilas, esplenomegalia a 5 cm DRCI. Laboratorio: Hb 8.8 g/dl, Hcto 27%, leucocitos: 47000/µl, linfocitos 88%, neutrófilos 7%, monocitos 1%, basófilos 0%, eosinófilos 0%, plaquetas 85000/µl. ¿Cuál es el diagnóstico más probable?", o:["Mieloma","Linfoma","Leucemia mieloide crónica","Leucemia linfática crónica","Mononucleosis infecciosa"], c:3, e:"La linfocitosis marcada y persistente con adenopatías y esplenomegalia en un adulto mayor es característica de la leucemia linfática crónica."},
{ex:"2022-A", n:25, area:"MED", tema:"Neumonía adquirida en la comunidad", q:"En las neumonías extrahospitalarias. ¿Cuál es un factor de riesgo para el deterioro temprano?", o:["pH mayor de 7.3","Albúmina sérica de 4.5 mg/dl","Infiltrados multilobares en radiografía de tórax","Saturación de oxígeno de 96%","Sodio sérico de 138 mg/dl"], c:2, e:"El compromiso radiológico multilobar es un factor pronóstico de gravedad y deterioro temprano en la neumonía adquirida en la comunidad; los demás valores listados están dentro de rangos normales."},
{ex:"2022-A", n:26, area:"SP", tema:"Principios de gestión en salud", q:"A qué principio corresponde el siguiente enunciado: \"Justifica la inversión de programas de salud con utilización de evidencia, ciencia y mejores prácticas para el logro óptimo de resultados en áreas de grandes necesidades\"", o:["Proactividad","Efectividad","Eficiencia","Vigilancia","Equidad"], c:1, e:"El uso de evidencia y mejores prácticas para lograr resultados óptimos corresponde al principio de efectividad en la gestión de programas de salud."},
{ex:"2022-A", n:27, area:"MED", tema:"Hemorragia digestiva alta (shock)", q:"Mujer de 60 años, desde hace 1 semana presenta cansancio, epigastralgias que calman con alimentos e hiporexia. Examen: palidez de piel y mucosas, hoy presenta melena por lo que acude a emergencia. Examen: PA 110/60 mmHg en decúbito y 90/50 mmHg sentado, FC 100X' en decúbito y 110X' sentada; abdomen blando, depresible y dolor leve en epigastrio. Según la valoración inicial. ¿Cuál es el porcentaje de volumen sanguíneo aproximado que ha perdido?", o:["Más de 40","5- 10","menos de 5","30-40","10- 20"], c:4, e:"La presencia de cambios ortostáticos (caída de PA y aumento de FC al sentarse) sin hipotensión en decúbito corresponde a una pérdida aproximada de 10-20% del volumen sanguíneo (shock hemorrágico clase II)."},
{ex:"2022-A", n:28, area:"CIR", tema:"Fractura de base de cráneo", q:"Varón de 32 años, llega a la emergencia, luego de haber sufrido caída pintando su casa. Sin antecedentes médicos de importancia. Examen: otorrea y rinorrea de secreción acuosa transparente. ¿Cuál es el nivel de la fractura?", o:["Hueso parietal","Bóveda del cráneo","Base del cráneo","Huesos faciales","Hueso temporal"], c:2, e:"La presencia simultánea de otorrea y rinorrea de LCR es característica de fractura de la base del cráneo, que compromete tanto el peñasco temporal como la fosa anterior."},
{ex:"2022-A", n:29, area:"PED", tema:"Escarlatina", q:"Niño de 4 años, presenta erupción difusa, eritematosa papular que inició en el cuello y se extendió a tronco y extremidades, siendo más intenso en los pliegues de codos, axilas e ingles, piel áspera al tacto, mejillas eritematosas y palidez alrededor de la boca; la lengua presenta papilas engrosadas con aspecto aframbuesado. ¿Cuál es el diagnóstico?", o:["Escarlatina","Eritema infeccioso","Kawasaki","Sarampión","Mononucleosis"], c:0, e:"El exantema en lija con acentuación en pliegues (líneas de Pastia), palidez perioral y lengua aframbuesada son el cuadro clásico de escarlatina por Streptococcus pyogenes."},
{ex:"2022-A", n:30, area:"GIN", tema:"Corioamnionitis (RPM)", q:"Gestante de 31 semanas, acude por pérdida de líquido desde hace 24 horas. Examen: T° 37.5 °C, FCF 155X'; contracciones uterinas esporádicas. Se realiza amniocentesis. ¿Cuál es el hallazgo en líquido amniótico que ayudaría a determinar la presencia de probable infección intrauterina?", o:["Polimorfonucleares disminuidos","PAPP - A elevada","Fibronectina presente","IGFBP - 1 ausente","Nivel bajo de glucosa"], c:4, e:"Un nivel bajo de glucosa en el líquido amniótico (consumida por bacterias y leucocitos) es un marcador clásico de infección intraamniótica/corioamnionitis subclínica."},
{ex:"2022-A", n:31, area:"CIR", tema:"Consolidación de fracturas", q:"¿Cuántas semanas dura la consolidación de fracturas de huesos largos en adultos?", o:["6 - 8","4 - 5","10 - 12","9 - 10","3 - 4"], c:0, e:"En huesos largos de adultos, la consolidación clínica se estima entre 6 y 8 semanas, aunque la remodelación completa puede tardar meses adicionales."},
{ex:"2022-A", n:32, area:"MED", tema:"Púrpura trombótica trombocitopénica", q:"Varón de 76 años, desde hace 15 días presenta gingivorragia; hoy presentó epistaxis. Examen: palidez, marcada, ictericia, petequias y equimosis múltiples, no visceromegalia, desorientado en tiempo y persona. Laboratorio: Hb 8 g/dl, plaquetas 3000/µl, leucocitos normales, test de Coombs (-), bilirrubinas totales 4.5 mg/dl, bilirrubina indirecta 3.2 mg/dl, reticulocitos 15%, DHL 760 U/l. ¿Cuál es el diagnóstico más probable?", o:["Purpura trombocitopénica autoinmune","Púrpura trombótica trombocitopénica","Anemia aplásica","Lupus eritematoso sistémico","Leucemia linfocítica aguda"], c:1, e:"La combinación de anemia hemolítica microangiopática (Coombs negativo, reticulocitosis, DHL alta) con trombocitopenia severa y alteración neurológica es la péntada clásica de la PTT."},
{ex:"2022-A", n:33, area:"MED", tema:"Neuralgia del trigémino", q:"Mujer de 55 años, refiere crisis repentinas de dolor facial relampagueante e insoportable, en forma de pinchazos, que puede durar 15 minutos o más. ¿Cuál es la afectación anatómica?", o:["Nervio bucal","Nervio cigomático","VII par craneal","V par craneal","VI par craneal"], c:3, e:"El dolor facial lancinante y paroxístico es característico de la neuralgia del trigémino (V par craneal)."},
{ex:"2022-A", n:34, area:"GIN", tema:"Síndrome de transfusión feto-fetal", q:"En el Síndrome de transfusión feto-fetal, el gemelo \"donante\" puede desarrollar principalmente...", o:["policitemia.","déficit del neurodesarrollo.","parto pretérmino.","falla cardiaca.","oligohidramnios."], c:4, e:"El gemelo donante presenta hipovolemia, anemia, restricción de crecimiento y oligohidramnios; el receptor desarrolla hipervolemia, policitemia, polihidramnios e insuficiencia cardiaca."},
{ex:"2022-A", n:35, area:"MED", tema:"Neumonía neumocócica", q:"Varón de 22 años, desde hace tres días presente fiebre, tos y dolor toráxico. Examen: taquipnea, politirajes; Pulmones: vibraciones vocales aumentadas en tercio medio de hemitórax derecho, crepitantes y soplo tubárico. ¿Cuál es el agente etiológico probable?", o:["Acinetobacter sp","Streptococcus pneumoniae","Pseudomonas aeruginosa","Mycobacterium tuberculosis","Klebsella pneumoniae"], c:1, e:"El síndrome de condensación pulmonar típico (soplo tubárico, aumento de vibraciones vocales) en un adulto joven previamente sano es característico de neumonía neumocócica."},
{ex:"2022-A", n:36, area:"PED", tema:"Desarrollo psicomotor (lenguaje comprensivo)", q:"Según el test peruano de evaluación del desarrollo del niño en el área del lenguaje comprensivo; cuando se le ofrece una pelota a un niño y al pedírsela con una orden simple: \"Dame la pelota\", entrega el objeto. ¿A qué edad cronológica en meses corresponde?", o:["7","11","9","8","6"], c:1, e:"En la escala peruana de desarrollo, la ejecución de una orden verbal simple sin apoyo gestual («dame la pelota») se ubica alrededor de los 11 meses de edad. (Ítem específico de escala; verificar con la tabla oficial si se dispone de ella)."},
{ex:"2022-A", n:37, area:"CB", tema:"Composición sanguínea (leucocitos)", q:"¿Qué porcentaje del volumen sanguíneo, constituyen los leucocitos?", o:["1%","5%","3%","4%","2%"], c:0, e:"Los leucocitos, junto con las plaquetas, forman la capa leucocitaria (\"buffy coat\") que representa aproximadamente el 1% del volumen sanguíneo total; el resto se reparte entre plasma (~55%) y eritrocitos (~44%)."},
{ex:"2022-A", n:39, area:"PED", tema:"Púrpura de Henoch-Schönlein", q:"Varón de 5 años, presenta durante 3 días erupción máculo papular rosada y algunas equímosis en ambas piernas, desde hace 2 días dolor en rodillas, dolor abdominal postprandial y vómitos alimentarios. Examen: FC 88X', FR 18X', T° 37°C; pápulas rosadas confluentes, petequias en ambas piernas que se extienden a tobillos y nalgas; dolor al movilizar ambas rodillas, no signos de flogosis; abdomen: dolor difuso a la palpación profunda. ¿Cuál es el diagnóstico más probable?", o:["Vasculitis por hipersensibilidad","Trombocitopenia inmune primaria","Artritis reumatoide juvenil","Púrpura de Henoch-Schönlein","Poliartritis nudosa"], c:3, e:"Púrpura palpable en miembros inferiores/glúteos, artralgias sin flogosis franca y dolor abdominal conforman la tétrada clásica de la púrpura de Henoch-Schönlein."},
{ex:"2022-A", n:40, area:"MED", tema:"Síndrome coronario agudo (biomarcadores)", q:"Varón de 55 años, hace 4 horas presenta dolor retroesternal intenso que se irradia al cuello y hombro izquierdo, palpitaciones y diaforesis. Examen: PA 100/60 mmHg, FC 100X'; EKG de dudosa interpretación. ¿Qué prueba ideal solicitaría para aclarar el diagnóstico?", o:["Troponina","CK-MM","Transaminasas","Aldolasa","Deshidrogenasa láctica"], c:0, e:"La troponina es el biomarcador más sensible y específico de daño miocárdico, de elección cuando el EKG no es concluyente ante sospecha de síndrome coronario agudo."},
{ex:"2022-A", n:41, area:"MED", tema:"Estado hiperosmolar hiperglucémico", q:"Varón de 52 años, diabético es llevado a emergencia por presentar desde hace una semana somnolencia, hiporexia y deterioro progresivo del estado de conciencia. Hoy oligoanuria. Examen: soporoso, deshidratado; FR 24X', FC 98X'; pulmones: no estertores. Laboratorio: glucosa 700 mg/dl, pH 7.35, HCO3 25 mEq/dl, Cr 2.0 mg/dl. ¿Cuál es el diagnóstico?", o:["Acidosis láctica","Estado hiperosmolar","Cetoacidosis diabética","Encefalopatía urémica","Sepsis foco urinario"], c:1, e:"Glucosa muy elevada con pH y bicarbonato normales (sin acidosis) descarta cetoacidosis y configura un estado hiperosmolar hiperglucémico, típico de evolución subaguda en el adulto mayor."},
{ex:"2022-A", n:42, area:"GIN", tema:"Anemia en el embarazo", q:"Gestante a término, sin control previo. Laboratorio: Hb 9.7 g/dl, hematocrito 30%, VCM 75 fl. ¿Cuál es el diagnóstico?", o:["Anemia microcítica","Producción disminuida de glóbulos rojos","Anemia dilucional","Anemia macrocítica","Anemia normocítica"], c:0, e:"Un VCM de 75 fl (por debajo de 80 fl) define una anemia microcítica, la más frecuente en el embarazo por déficit de hierro."},
{ex:"2022-A", n:43, area:"PED", tema:"Anemia ferropénica (tratamiento)", q:"¿Cuánto tiempo en meses debe durar el tratamiento con hierro en los niños entre 6 meses y 11 años de edad, que han sido diagnosticados de anemia ferropénica?", o:["9","6","2","4","3"], c:1, e:"El esquema del MINSA para anemia ferropénica en niños de 6 meses a 11 años establece un tratamiento con hierro durante 6 meses continuos para normalizar la hemoglobina y reponer los depósitos."},
{ex:"2022-A", n:44, area:"PED", tema:"Hiperplasia suprarrenal congénita", q:"En el momento del nacimiento se aprecia que un niño presenta genitales externos ambiguos; no existe pene y el clítoris se encuentra significativamente aumentado. La evaluación cromosómica muestra un genotipo XX. Se descubre que tiene ovarios pero no testículos. Las pruebas confirman la ausencia congénita de la enzima corticosuprarrenal 21 β-hidroxilasa. ¿Cuál sería el tratamiento adecuado?", o:["Corrección quirúrgica y tratamiento hormonal","No requiere intervención hasta esperar desarrollo hormonal","Sólo tratamiento hormonal","Sólo tratamiento quirúrgico","Conducta expectante"], c:0, e:"La hiperplasia suprarrenal congénita por déficit de 21-hidroxilasa con virilización requiere corrección quirúrgica de los genitales ambiguos junto con reemplazo hormonal (glucocorticoide/mineralocorticoide) de por vida."},
{ex:"2022-A", n:45, area:"MED", tema:"Diabetes y enfermedad renal crónica", q:"¿Qué antidiabético indicaría a una mujer de 59 años con glucosa sanguínea 170 mg/dl y enfermedad renal crónica estadio 4?", o:["Glicazida","Glimepirida","Metformina","Linagliptina","Glibenclamida"], c:3, e:"La linagliptina se elimina predominantemente por vía hepatobiliar, por lo que no requiere ajuste de dosis y es segura en ERC estadio 4; la metformina y las sulfonilureas están contraindicadas o requieren evitarse por riesgo de acidosis láctica e hipoglicemia respectivamente."},
{ex:"2022-A", n:46, area:"MED", tema:"Nefropatía diabética", q:"Varón de 58 años, presenta hace 6 meses orinas espumosas y edema de miembros inferiores. Antecedente de diabetes mellitus 2, dese hace 5 años con tratamiento irregular. Examen: PA 140/90 mmHg, FC 98X'. Laboratorio: creatinina 1.2 mg/dl, Na 140 mEq/l, K 4 mEq/l. ¿Cuál es el tratamiento más adecuado para el control de la presión arterial?", o:["Enalapril","Nifedipino","Furosemida","Hidroclorotiazida","Propranolol"], c:0, e:"Los IECA (enalapril) son de elección en nefropatía diabética con proteinuria, ya que además de controlar la PA tienen efecto renoprotector al reducir la presión intraglomerular."},
{ex:"2022-A", n:47, area:"GIN", tema:"Situación transversa (prolapso de cordón)", q:"Primigesta de 31 años, sin control prenatal, con contracciones frecuentes e intensas. Examen: AU 30 cm; FCF 132X'; TV dilatación de 6 cm, se palpa que el hombro fetal se ofrece hacia la pelvis. ¿Cuál es la complicación más frecuente que podría ocurrir?", o:["Prolapso de cordón","Daño del plexo braquial","Prolapso de brazo","D.P.P.","Ruptura uterina"], c:0, e:"En la situación transversa (presentación de hombro), el mal acoplamiento entre la presentación y la pelvis favorece la rotura precoz de membranas con prolapso de cordón, complicación más frecuente y grave."},
{ex:"2022-A", n:48, area:"SP", tema:"Desastres y enfermedades transmisibles", q:"De acuerdo al potencial epidémico de enfermedades transmisibles pos desastres, es más probable que se presente un síndrome diarreico agudo no específico si hay...", o:["hacinamiento.","falta de control bromatológico.","elevación la temperatura ambiental.","contaminación de agua y alimentos.","alimentación en masa."], c:3, e:"Tras un desastre, la contaminación fecal del agua y los alimentos es el determinante principal de brotes de enfermedad diarreica aguda por transmisión fecal-oral."},
{ex:"2022-A", n:49, area:"SP", tema:"Diseños de estudio epidemiológico", q:"¿Cuál es el diseño de estudio que permite medir el efecto de los tratamientos en la pandemia de COVID-19 en aquellos que tuvieron factores de exposición diversa, puede calcularse la tasa de incidencia, además de describir la historia natural de la enfermedad?", o:["Ensayo comunitario","Ensayo clínico","Transversal analítico","Cohorte","Caso control"], c:3, e:"El estudio de cohorte sigue a expuestos y no expuestos en el tiempo, permite calcular tasas de incidencia y describir la historia natural de la enfermedad, a diferencia del caso-control o el transversal."},
{ex:"2022-A", n:50, area:"MED", tema:"Catatonia", q:"Varón de 25 años, hospitalizado por diagnóstico de tuberculosis cerebral e infección por VIH, cursa con ausencia de actividad psicomotora, resistencia leve y constante al cambio de postura al ser examinado, respuesta verbal ausente y ecopraxia. Tomografía cerebral normal. ¿Cuál es el cuadro clínico que presenta el paciente?", o:["Catatonia","Delirium tremens","Estupor","Delirio","Esquizofrenia"], c:0, e:"El mutismo, la resistencia a la movilización pasiva (flexibilidad cérea) y la ecopraxia son signos característicos de un síndrome catatónico, frecuente en contexto de enfermedad médica/neuroinfección."},
{ex:"2022-A", n:51, area:"MED", tema:"Antidiabéticos orales (secretagogos)", q:"¿Cuál de los siguientes fármacos, tiene como mecanismo de acción incrementar la secreción de insulina por las células beta del páncreas?", o:["Metformina","Acarbosa","Empaglifozina","Glimepirida","Linagliptina"], c:3, e:"Las sulfonilureas como la glimepirida estimulan la secreción de insulina cerrando los canales de K-ATP de la célula beta; metformina, acarbosa, empagliflozina y linagliptina actúan por otros mecanismos no secretagogos directos."},
{ex:"2022-A", n:52, area:"MED", tema:"Otitis externa maligna", q:"Diabético de 68 años, desde hace 3 semanas presenta dolor persistente de oídos, con cefalea y prurito; desde hace 5 días secreción purulenta por el oído derecho. Examen: PA 150/80 mmHg, FC 95X', T° 38°C. Otoscopía: tejido de granulación descamativo en el piso del CAE, con zonas de necrosis. Cultivo de secreción positivo para Pseudomona. ¿Cuál es el diagnóstico?", o:["Sinusitis crónica","Otitis media crónica","Otitis externa crónica","Otitis externa maligna","Otitis media aguda"], c:3, e:"El paciente diabético con tejido de granulación y necrosis en el CAE, dolor intenso y cultivo positivo para Pseudomonas aeruginosa es el cuadro típico de otitis externa maligna (necrotizante)."},
{ex:"2022-A", n:53, area:"GIN", tema:"Soporte pélvico (niveles de DeLancey)", q:"¿Cuáles son las estructuras que forman parte del Nivel II del sistema de sostén del útero y la vagina?", o:["Músculo elevador del ano y fascia endopélvica","Uniones paravaginales hacia el arco tendíneo","Ligamentos uterosacros y ligamentos cardinales","Cuerpo perineal y hiato genital","Porción distal de la vagina"], c:1, e:"En la clasificación de DeLancey, el Nivel II corresponde a las uniones paravaginales laterales hacia el arco tendíneo de la fascia pélvica; el Nivel I son los ligamentos uterosacros/cardinales y el Nivel III el cuerpo perineal."},
{ex:"2022-A", n:54, area:"PED", tema:"Deficiencia de zinc (acrodermatitis enteropática)", q:"Lactante de 4 meses que inició alimentación con fórmula hace 2 meses, presenta diarrea crónica y lesiones dérmicas extensas vesículoampollosas eczematosas, secas, descamativas, psoriasiformes, que abarcan mejillas, zona perioral, codos, tobillos; retraso del crecimiento; alopecía; infecciones bacterianas recurrentes. ¿En qué deficiencia de micronutriente sospecha?", o:["Zinc","Hierro","Cobre","Calcio","Magnesio"], c:0, e:"La tríada de dermatitis periorificial/acral, diarrea crónica y alopecia es característica de la deficiencia de zinc (acrodermatitis enteropática)."},
{ex:"2022-A", n:55, area:"MED", tema:"Shock séptico", q:"Varón de 68 años, portador de sonda vesical, acude a emergencia por insuficiencia respiratoria y fiebre. Examen: soporoso; PA 90/60 mmHg, FC 98X', FR 22X'; geniturinario presencia de sonda foley con volumen de orina escasa y purulenta. Laboratorio: leucocitosis con deviación izquierda. ¿Qué espera encontrar?", o:["Nivel sérico de lactato disminuido","Presión de la oclusión de la arteria pulmonar aumentada","Disminución de liberación de óxido nitroso","Resistencia vascular sistémica está aumentada","Gasto cardiaco normal o aumentado"], c:4, e:"En la fase temprana (hiperdinámica) del shock séptico hay vasodilatación por exceso de óxido nítrico, con disminución de la resistencia vascular sistémica y un gasto cardiaco normal o aumentado como mecanismo compensador; el lactato está elevado, no disminuido."},
{ex:"2022-A", n:56, area:"PED", tema:"Bronquiolitis aguda", q:"Varón de 5 meses, traído a emergencia por dificultad respiratoria marcada, inició hace 3 días con rinorrea, tos persistente, fiebre y rechazo a la lactancia. Sin antecedentes patológicos. Examen: T 37.5°C, FC 124X', FR 54X', SatO2 92%; retracciones intercostales, supraesternal, disbalance tóracoabdominal; tórax y pulmones: sibilancias inspiratorias y espiratorias en ACP. ¿Cuál es el diagnóstico más probable?", o:["Laringotraqueitis","Reflujo gastroesofágico","Bronquiolitis aguda","Insuficiencia cardíaca","Tos ferina"], c:2, e:"Primer episodio de sibilancias con pródromo catarral en un lactante menor de 2 años es el cuadro clásico de bronquiolitis aguda, generalmente por VSR."},
{ex:"2022-A", n:57, area:"PED", tema:"Vacuna de varicela", q:"¿Qué tipo de vacuna es la que se aplica contra la varicela?", o:["RNA","Virus inactivados","Virus vivo atenuado","Recombinante","Conjugada"], c:2, e:"La vacuna contra la varicela es de virus vivo atenuado (cepa OKA)."},
{ex:"2022-A", n:58, area:"GIN", tema:"Toxicidad por sulfato de magnesio", q:"Gestante de 32 semanas, ingresa por eclampsia, presenta oliguria sostenida. Examen: PA 200/80 mmHg; recibe múltiples fármacos. En horas presenta letargia, debilidad progresiva y disminución de los reflejos osteotendinosos. ¿Cuál es el fármaco causante de dichos hallazgos?", o:["Labetalol","Gluconato de calcio","Nifedipino","Sulfato de magnesio","Clonidina"], c:3, e:"La abolición de reflejos osteotendinosos, letargia y debilidad en una paciente oligúrica que recibe sulfato de magnesio son signos tempranos de toxicidad, ya que su excreción es renal y se acumula con la oliguria."},
{ex:"2022-A", n:59, area:"GIN", tema:"Shock hemorrágico (embarazo ectópico)", q:"Mujer 35 años es llevada a emergencia por sangrado vaginal profuso desde hace 12 horas. Examen: soporosa, pálida, frialdad de extremidades. PA 90/60 mmHg, FC 110X'. Eco fast: embarazo ectópico roto. ¿Cuál es el tratamiento inicial?", o:["Norepinefrina","Albumina","Dobutamina","Corticoides","Cristaloides"], c:4, e:"Ante shock hemorrágico, la reanimación inicial se hace con cristaloides endovenosos mientras se prepara el manejo quirúrgico definitivo del embarazo ectópico roto."},
{ex:"2022-A", n:60, area:"MED", tema:"Cetoacidosis diabética (tratamiento)", q:"Mujer de 56 años, con diabetes mellitus insulinodependiente. Enfermedad vírica reciente le causó pérdida de apetito, fiebre y vómitos; por disnea fue ingresada a UCI. Examen: sequedad de membranas mucosas y disminución de la turgencia cutánea; respiración profunda y rápida. Laboratorio: orina contiene glucosa y cetonas. ¿Cuál es el tratamiento adecuado?", o:["Antidiabéticos orales","Hidratación e insulina","Antivirales","Sólo Insulina","Hidratación y antibióticos"], c:1, e:"La respiración de Kussmaul, deshidratación y cetonuria confirman cetoacidosis diabética; el pilar del tratamiento es la hidratación endovenosa junto con insulina."},
{ex:"2022-A", n:61, area:"PED", tema:"Lactancia materna exclusiva", q:"Neonato de una semana de edad que recibe lactancia materna exclusiva; madre pregunta si esta bien dar a su hijo media onza de agua una vez por día, porque donde vive la temperatura ambiental es de 36°C. ¿Cuál es la respuesta debida?", o:["No, porque hay riesgo que el agua esté contaminada","Sí, porque así evita que el niño se deshidrate","Sí, para disminuir la densidad calórica de la leche en climas cálidos","Es controversial ofertar agua adicional al neonato","No, porque la leche materna tiene suficiente agua"], c:4, e:"La leche materna exclusiva cubre completamente los requerimientos de agua del lactante, incluso en climas cálidos; no se recomienda ofrecer agua adicional antes de los 6 meses."},
{ex:"2022-A", n:62, area:"CB", tema:"Receptores de TSH (enfermedad de Graves)", q:"Mujer de 40 años, acude por fatiga, insomnio, palpitaciones y baja de peso. Examen: FC 100X'; piel tibia y húmeda; bocio palpable. Usted sospecha de la presencia de inmunoglobulinas que se unen los receptores de TSH ubicados en ...... de la célula del folículo tiroideo.", o:["membrana basal","interior de los lisosomas","retículo endoplásmico","el coloide","borde luminal"], c:0, e:"Los receptores de TSH se localizan en la membrana basal (basolateral) del tirocito, orientada hacia el torrente sanguíneo, sitio donde actúan tanto la TSH como las inmunoglobulinas estimulantes en la enfermedad de Graves."},
{ex:"2022-A", n:63, area:"PED", tema:"Escabiosis", q:"Niño de 5 años, presenta desde hace un mes prurito generalizado a predominio nocturno. Examen: se evidencia en piel de muñecas, espacios interdigitales, tobillos, glúteos y genitales erupción micropapular eritematosa; en tronco y extremidades micro costras puntiformes de distribución lineal. ¿Cuál es el tratamiento de elección?", o:["Corticoides tópicos","Cremas azufradas","Permetrina","Antihistamínicos orales","Retinoides"], c:2, e:"El prurito nocturno con lesiones en espacios interdigitales y surcos lineales es característico de escabiosis; la permetrina al 5% es el tratamiento tópico de elección."},
{ex:"2022-A", n:64, area:"MED", tema:"Meningitis tuberculosa", q:"Varón de 48 años VIH negativo; desde hace 3 semanas presenta fatiga, malestar general. Hace una semana fiebre, cefalea y vómitos. Examen: PA 120/60 mmHg; FC 60X', FR 18X', T 39.6°C; somnoliento, rigidez de nuca y Kerning presentes. Laboratorio: Glucosa 100mg/dl, LCR turbio, Presión 24 cm de H2O, leucocitos 450/µl (100% mononucleares), glucosa 40 mg/dl, proteinas 180 mg/dl. ¿Qué meningitis es la más probable?", o:["Sifilítica","Tuberculosa","Viral","Bacteriana","Criptococósica"], c:1, e:"El curso subagudo (semanas), la pleocitosis mononuclear con proteínas muy elevadas y glucosa baja son característicos de meningitis tuberculosa, a diferencia de la bacteriana (curso agudo, predominio de polimorfonucleares)."},
{ex:"2022-A", n:65, area:"MED", tema:"Epilepsia focal (tratamiento)", q:"Mujer de 50 años, en forma brusca presenta movimientos tónico-clónicos en miembro superior izquierda que se iniciaron en dedos de la mano. EEG: descargas anormales en región cortical derecha que controla los movimientos de la mano. ¿Qué anticonvulsivante de primera elección usaría?", o:["Fenobarbital","Ácido valproico","Carbamazepina","Topimarato","Gabapentina"], c:2, e:"Ante una crisis focal motora (jacksoniana) confirmada por foco cortical en el EEG, la carbamazepina es el anticonvulsivante clásico de primera elección para crisis focales."},
{ex:"2022-A", n:66, area:"SP", tema:"Metaanálisis", q:"¿Cuál es la metodología cuantitativa que resume los hallazgos de estudios con diferentes diseños?", o:["Estudio de cohorte multicéntrico","Metaanálisis","Estudios ecológicos","Ensayo clínico con más de dos brazos","Revisión sistemática"], c:1, e:"El metaanálisis es la técnica estadística cuantitativa que combina y resume los resultados numéricos de múltiples estudios, incluso de diseños diferentes, en una medida de efecto conjunta."},
{ex:"2022-A", n:67, area:"PED", tema:"Atresia esofágica", q:"Neonato de 2 semanas, traído por la madre, quien refiere que presenta eliminación de saliva abundante luego de iniciar la lactancia acompañado de tos y \"atoro\". Examen: abdomen distendido, blando y depresible. Se diagnostica atresia esofágica y se desea saber si existe la fístula traqueoesofágica. ¿Cuál es el examen a solicitar?", o:["Rx. esófago con contraste","Tomografía de tórax","Mediastinoscopía","Toracoscopía","Rx. simple de tórax"], c:4, e:"La presencia de aire en el estómago/abdomen en una radiografía simple de tórax-abdomen confirma de forma sencilla la existencia de una fístula traqueoesofágica distal asociada a la atresia."},
{ex:"2022-A", n:68, area:"GIN", tema:"Distocia de hombros", q:"Gestante en periodo expulsivo; luego de salida de cabeza fetal Ud. nota que el hombro se encuentra impactado sobre la sínfisis materna. Procede a realizar la maniobra de Mc Roberts con presión suprapúbica pero el hombro anterior no es liberado. ¿Cuál es el procedimiento a seguir?", o:["Sinfisiotomía","Cleidotomía","Maniobra de Rojas","Maniobra de Zavanelli","Extracción del brazo posterior"], c:4, e:"Tras fallar McRoberts con presión suprapúbica, el siguiente paso en el algoritmo de distocia de hombros es intentar maniobras internas, como la extracción del brazo posterior, antes de recurrir a medidas de rescate como Zavanelli."},
{ex:"2022-A", n:69, area:"GIN", tema:"Atonía uterina (factores de riesgo)", q:"¿Cuál es un factor de riesgo para atonía uterina?", o:["Trabajo de parto prolongado","Desgarro vaginal","RCIU","Alumbramiento dirigido","Prematuridad"], c:0, e:"El trabajo de parto prolongado agota la contractilidad del miometrio y es un factor de riesgo reconocido para atonía uterina; el alumbramiento dirigido, en cambio, es una medida preventiva."},
{ex:"2022-A", n:70, area:"GIN", tema:"Embarazo postérmino", q:"Gestante de 41 semanas por ecografía del primer trimestre, con pruebas de bienestar fetal adecuadas. TV: cérvix blando, anterior, dilatación 0, borramiento 50% y estación 0. ¿Cuál es el manejo?", o:["Observación","Inducir el parto","Repetir las pruebas en una semana","Programar para cesárea","Madurar el cérvix"], c:1, e:"A las 41 semanas está indicada la inducción del parto; dado que el cérvix ya es favorable (blando, borrado 50%), se puede iniciar inducción directa sin necesidad de maduración cervical previa."},
{ex:"2022-A", n:71, area:"PED", tema:"Varicela", q:"Lactante mujer de 10 meses, presenta desde hace 2 días fiebre de 39°C, llanto intenso y rechazo a la lactancia; hace un día erupción en cara y cuerpo. Examen: T° 39°C, FC 124X', FR 34X'; pápulas eritematosas, vesícula, algunas costras en cara, cuero cabelludo, tronco y zona proximal de las extremidades; lesiones ulceradas en la mucosa orofaríngea y vagina. ¿Cuál es el diagnóstico más probable?", o:["Viruela simia","Eritema infeccioso","Rickettsiosis exantemática","Varicela","Roseola infantil"], c:3, e:"La coexistencia de lesiones en distintos estadios (pápula, vesícula y costra simultáneamente) es el sello distintivo de la varicela, a diferencia de la viruela/mpox donde las lesiones son sincrónicas (mismo estadio en todo el cuerpo); las úlceras en mucosas también pueden verse en varicela extensa."},
{ex:"2022-A", n:72, area:"CIR", tema:"Escala de Glasgow", q:"Mujer de 28 años, sufre agresión con objeto contundente en la cabeza, presentando cefalea y desorientación. Examen: función motora: localiza dolor al estímulo; muestra confusión al preguntarle por tiempo y espacio; no muestra apertura ocular. ¿Qué calificación le corresponde en la Escala de Glasgow?", o:["13","9","12","8","10"], c:4, e:"Apertura ocular ausente (1) + respuesta verbal confusa (4) + localiza el dolor (5) = Glasgow 10."},
{ex:"2022-A", n:73, area:"GIN", tema:"Diabetes gestacional (tamizaje)", q:"Gestante obesa de 12 semanas que acude a consulta, tiene el antecedente de bebe macrosómico en parto anterior. Se le solicita glicemia en ayuna la cual sale normal. ¿Cuál es el paso a seguir?", o:["Repetir su glicemia a la semana","Solicitar test de tolerancia a las 28 semanas","Controlar su glicemia cada dos semanas","Dar dosis profiláctica de insulina","Continuar con su control prenatal normal"], c:1, e:"Aun con glicemia en ayunas normal en el primer control, la paciente con factores de riesgo (obesidad, macrosomía previa) debe someterse al tamizaje estándar con test de tolerancia oral a la glucosa entre las 24-28 semanas."},
{ex:"2022-A", n:74, area:"PED", tema:"Hipokalemia por beta-agonistas", q:"Niño de 5 años con asma persistente severa, usa habitualmente inhaladores agonista beta adrenérgicos y corticoides. Visto en emergencia por severa dificultad respiratoria, le indican nebulizaciones con salbutamol cada 20 minutos, por dos horas y corticoide sistémico. Si el paciente empieza a presentar arritmias. ¿Qué disturbio metabólico explica este evento?", o:["Hipernatremia","Hipercalcemia","Hiperkalemia","Hipocalcemia","Hipokalemia"], c:4, e:"Los beta-agonistas inhalados en dosis repetidas desplazan potasio hacia el interior celular, generando hipokalemia, que puede favorecer arritmias."},
{ex:"2022-A", n:75, area:"GIN", tema:"Manejo activo del alumbramiento", q:"Se procederá al manejo activo del tercer periodo del trabajo de parto, siguiendo a la salida del hombro anterior o inmediatamente después del nacimiento del bebé y antes del clampaje y corte del cordón. ¿Cuál es la droga de elección a emplear?", o:["Misoprostol","Sintometrina","Oxitocina","Ergometrina","Carboprost"], c:2, e:"La oxitocina es el uterotónico de primera elección en el manejo activo del alumbramiento, administrada tras el nacimiento del hombro anterior o el bebé."},
{ex:"2022-A", n:76, area:"MED", tema:"Absceso pulmonar", q:"Varón de 48 años diabético, consulta por presentar hace una semana tos productiva, dolor torácico y disnea; con reflujo gastroesofágico. Examen: MEG, FC 98X', FR 24X', T° 38°C. Tórax y pulmones: politirajes, VV abolidos; matidez; MV ausente. Rx de Tórax: cavidad de pared gruesa con nivel hidroaéreo. ¿Qué prueba diagnóstica solicitaría?", o:["Mielocultivo","Hemograma","Tomografía pulmonar","Cultivo de esputo","Aspiración transtraqueal"], c:4, e:"En el absceso pulmonar de probable origen aspirativo (por RGE), la muestra de esputo se contamina con flora orofaríngea y no discrimina bien anaerobios; la aspiración transtraqueal evita esa contaminación y es la muestra clásicamente recomendada para cultivo anaeróbico fiable."},
{ex:"2022-A", n:77, area:"MED", tema:"Colitis pseudomembranosa", q:"Mujer de 35 años, hospitalizada, en tratamiento con clindamicina EV, al quinto día presenta diarreas acuosas sanguinolentas con moco y dolor abdominal tipo cólico. Examen: abdomen distendido, dolor fosa iliaca izquierda. ¿Cuál es el agente etiológico más probable?", o:["Giardia lamblia","Clostridium difficile","Campilobacter jejuni","Escherichia coli","Entamoeba histolytica"], c:1, e:"La diarrea asociada al uso de clindamicina (y otros antibióticos de amplio espectro) es clásicamente causada por Clostridium difficile."},
{ex:"2022-A", n:78, area:"GIN", tema:"Tamizaje de trisomía 21", q:"Mujer de 35 años, G1P0, con 10 semanas de gestación; no antecedentes; acude a su primer control prenatal. Ella desea conocer cuál es el riesgo de que su bebé pueda presentar trisomía 21. ¿Cuál sería la mejor recomendación?", o:["Realizar amniocentesis","Biopsia de vellosidades coriales","Determinar AFP","Valorar hueso nasal y ductus venoso","Tamizaje con test combinado"], c:4, e:"El tamizaje no invasivo de elección para trisomía 21 en el primer trimestre es el test combinado (translucencia nucal + marcadores bioquímicos), reservando los procedimientos invasivos para casos de alto riesgo."},
{ex:"2022-A", n:79, area:"CIR", tema:"Fijación externa", q:"¿En qué tipo de fracturas o condiciones se utiliza la fijación externa?", o:["Sin lesiones vasculares asociadas","Pacientes inestables pero que tolere anestesia","Abiertas","En pacientes inestables que toleren hemorragia","Complejas que precisan reducción abierta y fijación interna"], c:2, e:"La fijación externa es de elección en fracturas abiertas y contaminadas, ya que evita la colocación de material interno en una zona con riesgo de infección, además de permitir control de partes blandas."},
{ex:"2022-A", n:80, area:"CIR", tema:"Anestesia local (bloqueo infraorbitario)", q:"Varón de 30 años, luego de una gresca presenta herida profunda a nivel del pómulo. Para poder suturar adecuadamente. ¿Cuál es la ubicación anatómica en donde se debe de aplicar la anestesia?", o:["Fosa retromolar","Nasofaríngeo","Región infraorbitaria","Directo en la herida","Maxilar superior"], c:2, e:"El bloqueo del nervio infraorbitario a nivel de la región infraorbitaria anestesia la zona malar/pómulo de forma más eficaz y menos dolorosa que la infiltración directa en la herida."},
{ex:"2022-A", n:81, area:"CB", tema:"Papilas gustativas (COVID y disgeusia)", q:"Varón de 35 años, que el año pasado presentó COVID-19; no tuvo necesidad de uso de oxígeno ni de hospitalización. Sin embargo, refiere persistencia de no percibir sabores salados. ¿Qué estructura de la lengua está comprometida en dicha sintomatología?", o:["Las papilas caliciformes","Las papilas foliadas","Las papilas fungiformes","Las células de soporte","Las microvellosidades"], c:2, e:"Las papilas fungiformes, distribuidas en los dos tercios anteriores de la lengua, son las principales responsables de la percepción de sabores dulces y salados."},
{ex:"2022-A", n:82, area:"MED", tema:"Trastorno narcisista de personalidad", q:"Abogada de 43 años, se queja siempre ante su jefe de ser postergada en el estudio a pesar de sus grandes méritos; sin embargo, su rendimiento es promedio. Grita a las asistentes si no hacen de inmediato lo que les ordena; afirma continuamente que es la mejor abogada del estudio y se enoja si elogian a su colega, de mejor trato con el personal, profesora universitaria y que hace trabajos de mayor calidad que el suyo. ¿Cuál es el trastorno de personalidad más probable?", o:["Narcisista","Histriónica","Obsesiva","Esquizotípica","Neurótica"], c:0, e:"La grandiosidad no correlacionada con el desempeño real, la necesidad de admiración y la envidia hacia el éxito ajeno son rasgos centrales del trastorno narcisista de personalidad."},
{ex:"2022-A", n:83, area:"MED", tema:"Glaucoma agudo de ángulo cerrado", q:"Mujer de 55 años, hipermétrope, con dolor intenso en ojo derecho, náuseas y vómitos de inicio reciente. Examen: ojo derecho con agudeza visual cuenta dedos a 30 cm, inyección conjuntival, midriasis y edema corneal. ¿Cuál es el diagnóstico?", o:["Glaucoma agudo de ángulo cerrado","Uveitis anterior aguda","Neuritis óptica anterior","Desprendimiento de retina","Glaucoma agudo de ángulo abierto"], c:0, e:"La hipermetropía (predispone a cámara anterior estrecha), dolor ocular intenso con náuseas/vómitos, midriasis media fija y edema corneal son el cuadro clásico del glaucoma agudo de ángulo cerrado."},
{ex:"2022-A", n:84, area:"PED", tema:"Incompatibilidad ABO", q:"Neonato de 12 horas de vida, producto de primera gestación, nacido de parto pretérmino a las 35 semanas, peso de 2 kilos; alimentado con lactancia materna exclusiva con succión débil, presenta ictericia hasta el cuello; madre grupo O(+), bebe A(-); Billirrubina total 10 mg/dl, BD 2 mg/dl. ¿Qué explica la aparición de ictericia?", o:["Incompatibilidad sanguínea","Problema colestásico","Leche materna","Prematuridad","Asfixia neonatal"], c:0, e:"Madre grupo O y bebé grupo A configuran una incompatibilidad ABO, causa de hemólisis e ictericia de aparición precoz (antes de las 24 h), independientemente del Rh (aquí no hay incompatibilidad Rh, pues la madre es Rh+)."},
{ex:"2022-A", n:85, area:"MED", tema:"Tuberculosis pulmonar", q:"Mujer de 35 años, consulta por presentar hace 3 semanas, tos seca, sudoración nocturna, sensación de alza térmica y astenia. Examen: FR 18X', FC 88X'; pulmones: soplo tubárico en el ápex derecho. ¿Cuál es el diagnóstico más probable?", o:["Aspergilosis pulmonar","Neumonía por COVID-19","Faringitis crónica","Tuberculosis pulmonar","Bronquitis crónica"], c:3, e:"Síntomas de más de 2-3 semanas de evolución (tos, sudoración nocturna, astenia) con compromiso apical son característicos de tuberculosis pulmonar."},
{ex:"2022-A", n:86, area:"CIR", tema:"Torsión testicular", q:"Adolescente de 14 años, hace 30 minutos presenta dolor súbito en región escrotal izquierda con aumento de volumen. Examen: asimetría a predominio del testículo izquierdo doloroso a la palpación. ¿Cuál es el examen a solicitar para el diagnóstico?", o:["Arteriografía","Tomografía","Resonancia magnética","Eco Doppler","Gamagrafía"], c:3, e:"Ante sospecha de torsión testicular, la ecografía Doppler testicular es el examen de elección por su rapidez y capacidad de evaluar el flujo sanguíneo."},
{ex:"2022-A", n:87, area:"MED", tema:"Ictus embólico (fibrilación auricular)", q:"Varón de 30 años, que desde hace dos días presenta en forma brusca hemiplejía derecha directa, afasia psicomotriz. Examen CV: tonos cardiacos irregulares y asincrónicos. ¿Cuál es el diagnóstico neurológico probable?", o:["Trombosis cerebral","Ataque isquémico transitorio","Hemorragia cerebral","Embolia cerebral","Aneurisma cerebral"], c:3, e:"El inicio súbito de un déficit focal en presencia de arritmia cardiaca (probable fibrilación auricular) orienta a un ictus de origen embólico cardiogénico."},
{ex:"2022-A", n:88, area:"GIN", tema:"BIRADS (categorías de mamografía)", q:"Mujer de 54 años acude a consultorio por un resultado de mamografía que reporta Birads 0. ¿Cuál es la medida a seguir?", o:["Marcadores oncogénicos","Ecografía de mamas","Marcadores genéticos","Biopsia de mama","Resonancia magnética"], c:1, e:"BIRADS 0 indica un estudio incompleto que requiere imágenes adicionales (proyecciones complementarias o ecografía mamaria) antes de poder categorizar el hallazgo."},
{ex:"2022-A", n:89, area:"GIN", tema:"Neuroprotección fetal (sulfato de magnesio)", q:"Gestante de 29 años, G2 P0101, de 30 semanas, control prenatal adecuado; acude por presentar contracciones uterinas regulares. Examen: AU 27 cm, FCF 140X'; dilatación cervical 1 cm. El empleo del sulfato de magnesio en este caso permitirá...", o:["reducir la incidencia de infección intrauterina.","disminuir el riesgo de parálisis cerebral.","demostrar su acción tocolítica en estos casos.","disminuir la tasa de cesáreas.","la profilaxis de convulsiones neonatales."], c:1, e:"En amenaza de parto pretérmino antes de las 32 semanas, el sulfato de magnesio se usa por su efecto neuroprotector fetal, disminuyendo el riesgo de parálisis cerebral; su efecto tocolítico es débil y no es la indicación principal."},
{ex:"2022-A", n:90, area:"GIN", tema:"Sangrado uterino anormal (biopsia endometrial)", q:"Paciente obesa de 42 años que presenta sangrado irregular desde hace 6 años, a la ecografía muestra un endometrio de 14 mm. ¿Cuál es el manejo más adecuado?", o:["Biopsia de endometrio","Resección en cuña de ovario","Laparotomía","Histerectomía abdominal","Anticonceptivos orales"], c:0, e:"Ante sangrado uterino anormal crónico con endometrio engrosado (14 mm) en paciente obesa (factor de riesgo de hiperplasia/cáncer endometrial), la biopsia de endometrio es obligatoria antes de cualquier tratamiento."},
{ex:"2022-A", n:91, area:"PED", tema:"Lactancia materna (signos de alarma)", q:"Madre de recién nacido de 6 días de vida acude a consulta ambulatoria porque le preocupa no tener suficiente leche. ¿Cuál de los siguientes signos es el más confiable para confirmar su preocupación?", o:["Que el bebe duerme 15 horas al día","Llora cada dos horas para lactar con hambre","El bebé moja tres pañales al día","Se despierta en la noche varias veces para lactar","Que la leche materna es aguada"], c:2, e:"A los 6 días de vida se espera al menos 6 pañales mojados al día; mojar solo tres es un signo objetivo de aporte insuficiente de leche. Los demás datos (dormir, llorar, despertarse) pueden ser variantes normales."},
{ex:"2022-A", n:92, area:"CIR", tema:"Taponamiento cardiaco traumático", q:"Mujer de 56 años, sufre accidente de tránsito, golpeándose contra el timón del auto, por lo que acude a emergencia. Examen: PA 90/60mmHg, FC 96X´, SatO2 96%; se palpa pulso paradojal en inspiración, ingurgitación yugular; ruidos cardiacos disminuidos de intensidad. ¿Cuál es el examen para confirmar el diagnóstico?", o:["Tomografía de tórax","Ecocardiografía","Electrocardiograma","Rx. de tórax","Resonancia magnética de tórax"], c:1, e:"Ante la tríada de Beck (hipotensión, ingurgitación yugular, ruidos cardiacos apagados) más pulso paradójico tras trauma torácico, la ecocardiografía es el examen de elección para confirmar el taponamiento cardiaco."},
{ex:"2022-A", n:93, area:"PED", tema:"Fluidoterapia neonatal", q:"En la evaluación vespertina de un neonato a término de 3 Kg, en primer día de vida; el reporte de enfermería es que está presentando vómitos. Usted mide residuo gástrico y lo encuentra alto. Decide dejarlo en NPO por sospecha de obstrucción intestinal. ¿Qué solución indica en las primeras 24 horas?", o:["Dextrosa al 5%, 300 cc con ClNa 6 mEq","Dextrosa al 5%, 180 sin electrolitos","Dextrosa al 10%, 180 cc sin electrolitos","Dextrosa al 10%, 180ml, con ClNa 6 mEq","Solución salina o suero fisiológico 300 cc"], c:2, e:"En el primer día de vida el neonato no requiere aporte de electrolitos (contracción fisiológica del líquido extracelular); se indica dextrosa al 10% para cubrir el requerimiento calórico-hídrico basal sin electrolitos añadidos."},
{ex:"2022-A", n:94, area:"PED", tema:"Sarampión", q:"Niño de 4 años con síntomas catarrales y fiebre desde hace 5 días, es traído por tos y dificultad respiratoria. Examen: irritable, febril, rinorrea blanquecina, adenopatía cervical bilateral, exantema eritemato máculo papular en cara, tronco y extremidades, ojos con eritema conjuntival y secreción viscosa bilateral, mucosa oral con eritema en paladar y encías. MV presente, subcrepitos y roncantes diseminados. ¿En qué diagnóstico sospecha?", o:["Sarampión","Eritema infeccioso","Rubéola","Varicela","Roseola infantil"], c:0, e:"La tríada catarral (tos, coriza, conjuntivitis) con exantema céfalo-caudal y compromiso de mucosa oral es característica del sarampión."},
{ex:"2022-A", n:95, area:"PED", tema:"Pielonefritis aguda", q:"Lactante mujer de 8 meses, presenta desde hace 3 días fiebre, vómitos alimentarios e hiporexia. Antecedente: diarreas recurrentes y pobre ganancia pondoestatural. Examen: T° 39°C, FC 128 X', FR 24X' adelgazada, abdomen doloroso a la palpación profunda. Laboratorio: leucocitos18000/µl, neutrófilos 80%; examen de orina: leucocitos +100/campo, aglutinados, cilindros hemáticos, hematíes 30-50/campo. ¿Cuál es el diagnóstico?", o:["Síndrome nefrítico","Pielonefritis aguda","Urosepsis","Diarrea aguda infecciosa","Diarrea crónica"], c:1, e:"Fiebre, leucocitosis con neutrofilia y sedimento urinario con leucocituria masiva y cilindros hemáticos indican compromiso del parénquima renal (pielonefritis aguda), no solo cistitis baja."},
{ex:"2022-A", n:96, area:"PED", tema:"Cuerpo extraño en vía aérea", q:"Niño de 7 años, sin antecedente previo, súbitamente presenta disnea intensa, tos, estridor laríngeo, disfonía, insuficiencia respiratoria y agitación sicomotriz. ¿Cuál es el diagnóstico?", o:["Cuerpo extraño en laringe","Laringitis subglótica","Laringitis espasmódica","Espasmo bronquial agudo","Aspiración de sustancias tóxicas"], c:0, e:"El inicio súbito y sin pródromo catarral, con estridor y disfonía en un niño previamente sano, orienta fuertemente a aspiración de cuerpo extraño laríngeo."},
{ex:"2022-A", n:97, area:"CB", tema:"Cisternas subaracnoideas", q:"En relación a las cisternas subaracnoideas. ¿A qué cisterna corresponde, la que radica en la parte superior del cuerpo calloso y en la superficie superior del cerebelo?", o:["Pontina","Interpendicular","Cuadrigémina","Cerebelobulbar posterior","Quiasmática"], c:2, e:"La cisterna cuadrigémina se ubica por detrás del techo del mesencéfalo, entre el esplenio del cuerpo calloso y la cara superior del cerebelo."},
{ex:"2022-A", n:98, area:"PED", tema:"Estenosis pilórica hipertrófica", q:"RN varón, presenta vómitos no biliosos \"en proyectil\" intensificado en el curso de varios días, no tolera ni siquiera líquidos claros; a pesar del vómito recurrente, tiene un apetito voraz; la mamá menciona que evacua cada vez menos flatos. Examen: deshidratado; abdomen: se palpa tumoración pequeña en el cuadrante superior derecho con presencia de ondas gástricas visibles. ¿Cuál es el diagnóstico?", o:["Estenosis pilórica hipertrófica","Estenosis duodenal","Intususcepción","Atresia yeyunal","Duplicación intestinal"], c:0, e:"Vómitos no biliosos en proyectil, oliva pilórica palpable y ondas peristálticas visibles en un varón de pocas semanas son el cuadro clásico de estenosis hipertrófica del píloro."},
{ex:"2022-A", n:99, area:"CIR", tema:"Fractura de fémur (desplazamiento)", q:"Varón de 25 años, politraumatizado, se queja de dolor en muslo derecho. Examen: aumento de volumen y huellas de contusión directa en piel. Rx: muestra fémur con bordes fracturados con traslación y angulación. Clínicamente. ¿Qué se debe evaluar para considerar la fractura como desplazada?", o:["Herida extensa en piel","Falta de pulso poplíteo","Acortamiento y angulación","Gran edema del miembro afectado","Pulso pedio débil"], c:2, e:"Clínicamente, el desplazamiento de una fractura se traduce en acortamiento del miembro y angulación visible, correlato de la traslación/angulación observada en la radiografía."},
{ex:"2022-A", n:100, area:"CB", tema:"Desarrollo mamario", q:"¿Qué hormona promueve el desarrollo del sistema ductal de la mama?", o:["Activina","Progesterona","Estradiol","Relaxina","Oxitocina"], c:2, e:"El estradiol estimula el crecimiento y ramificación del sistema ductal mamario, mientras que la progesterona promueve el desarrollo lobuloalveolar."},

{ex:"2022-B", n:1, area:"MED", tema:"Gota (podagra) por diuréticos", q:"Varón de 50 años es llevado a emergencia por dolor intenso 10/10 a nivel de primer dedo de pie derecho. Antecedente: HTA en tratamiento triple. Examen: deshidratado, desorientado en tiempo, articulación metatarso falángica de primer dedo de pie con eritema, incremento de temperatura local y limitación al movimiento. ¿Qué fármaco es el causante de todos los hallazgos clínicos?", o:["Acetazolamida","Amlodipino","Carvedilol","Espironolactona","Hidroclotiazida"], c:4, e:"Los diuréticos tiazídicos como la hidroclorotiazida reducen la excreción renal de ácido úrico y son causa clásica de hiperuricemia y crisis de gota (podagra)."},
{ex:"2022-B", n:2, area:"MED", tema:"Artritis reactiva (síndrome de Reiter)", q:"¿Cuál es el primer cuadro ocular que se presenta en la artritis reactiva (síndrome de Reiter)?", o:["Queratitis","Escleritis","Conjuntivitis papilar","Glaucoma ángulo cerrado","Glaucoma ángulo abierto"], c:2, e:"La conjuntivitis es la manifestación ocular más frecuente y precoz de la artritis reactiva, formando parte de la tríada clásica junto con uretritis y artritis."},
{ex:"2022-B", n:3, area:"MED", tema:"Uretritis", q:"Adolescente varón de 16 años, desde hace una semana presenta disuria, polaquiuria. Examen: eritema y exudado mucoide en el meato uretral. ¿Cuál es el posible agente causal?", o:["Neiseria gonorrhoeae","Haemophilus ducreyi","Virus herpes tipo 2","Papiloma virus","Treponema pallidum"], c:0, e:"Entre las opciones disponibles, Neisseria gonorrhoeae es la causa bacteriana más frecuente de uretritis con secreción uretral en el varón joven sexualmente activo."},
{ex:"2022-B", n:4, area:"MED", tema:"Vejiga hiperactiva", q:"\"La urgencia urinaria usualmente acompañada de polaquiuria y nicturia, con o sin incontinencia urinaria de urgencia, en ausencia de infección urinaria u otra enfermedad obvia\" corresponde a:", o:["Hipermovilidad uretral","Vejiga hiperactiva","Vaciamiento anómalo","Hiperactividad del detrusor","Incontinencia urinaria mixta"], c:1, e:"Esta es la definición clínica (sindrómica) de vejiga hiperactiva según la ICS; la hiperactividad del detrusor es, en cambio, un hallazgo urodinámico, no un diagnóstico clínico."},
{ex:"2022-B", n:5, area:"CIR", tema:"Isquemia mesentérica aguda", q:"¿Cuál es el nivel de isquemia intestinal que alcanza una obstrucción aguda de la arteria mesentérica superior?", o:["Yeyuno hasta colon ascendente o transverso","Todo el marco cólico","Todo el yeyuno e ileon","Ileon, colon derecho y transverso","Duodeno, yeyuno e ileon"], c:0, e:"La arteria mesentérica superior irriga desde el yeyuno hasta los dos tercios proximales del colon transverso (incluyendo íleon y colon ascendente), territorio que se compromete en su oclusión aguda."},
{ex:"2022-B", n:6, area:"MED", tema:"Anemia megaloblástica (déficit B12)", q:"Varón de 64 años, acude por mareos, baja de peso, anorexia, adormecimiento de miembros inferiores, visión borrosa y por momentos delirio. Examen: palidez moderada, glositis. Neurológico: somnoliento y por momentos agitado. Laboratorio: Hb 10 g/dl, VCM 110 fl. Lámina periférica macro ovalocitos. TSH: 2 mU/L. ¿Cuál es el diagnóstico más probable?", o:["Anemia megaloblástica","Neuropatía metabólica","Demencia de Alzheimer","Coma mixedematoso","Hipotiroidismo"], c:0, e:"Macrocitosis marcada con macroovalocitos, glositis y síntomas neurológicos, con TSH normal (descarta causa tiroidea), es característico de anemia megaloblástica por déficit de vitamina B12."},
{ex:"2022-B", n:7, area:"MED", tema:"Hipotiroidismo (diagnóstico)", q:"Mujer de 45 años, desde hace 4 meses presenta hipersomnia, astenia, ronquera y estreñimiento. Examen: FC 60 X'; bradilalia; piel seca; ROT: fase de relajación prolongada. ¿Qué examen inicial solicitaría?", o:["TSH sérico","Ac anti-TPO","T3 libre","Antiroglobulina","Ecografía tiroidea"], c:0, e:"Ante un cuadro clínico sugestivo de hipotiroidismo, la TSH sérica es la prueba de tamizaje inicial de elección por su alta sensibilidad."},
{ex:"2022-B", n:8, area:"PED", tema:"Displasia de cadera (complicaciones)", q:"¿Cuál es la complicación más grave en el tratamiento de la displasia de cadera, en los lactantes menores de 6 meses?", o:["Subluxación residual","Displasia acetabular","Necrosis avascular de la epífisis femoral","Reluxación","Sinovitis transitoria"], c:2, e:"La necrosis avascular de la epífisis femoral proximal es la complicación más grave del tratamiento (por ejemplo, con arnés o reducción forzada) de la displasia de cadera en lactantes pequeños."},
{ex:"2022-B", n:9, area:"PED", tema:"Rubéola", q:"Niña de 2 años, presenta fiebre hace dos días, dolor faríngeo, anorexia, es traída por presentar erupción generalizada. Examen: FC 90X', FR 25X', T° 37°C, eritema en la cara y el cuello, pequeñas máculas irregulares, rosadas, que confluyen y se diseminan en tronco y extremidades; orofaringe con lesiones rosadas y petequias en paladar blando; adenopatías suboccipitales y retroauriculares de 1 cm de diámetro, dolorosas. ¿Cuál es el diagnóstico?", o:["Rubéola","Kawasaki","Mononucleosis","Sarampión","Eritema infeccioso"], c:0, e:"Fiebre baja, exantema rosado fino y las adenopatías retroauriculares/suboccipitales dolorosas junto con manchas de Forchheimer en paladar son clásicas de la rubéola."},
{ex:"2022-B", n:10, area:"SP", tema:"Reforma del estado (gobierno abierto)", q:"¿Cómo se llama aquel atributo de gobierno de reforma de estado en la que se es transparente, accesible a los ciudadanos, que sepa que tiene derechos y que el gobierno esté obligado a responder?", o:["Eficiente","Unitario","Descentralizado","Abierto","Orientado al ciudadano"], c:3, e:"La transparencia, el acceso ciudadano y la rendición de cuentas son atributos del concepto de gobierno abierto dentro de la reforma del Estado."},
{ex:"2022-B", n:11, area:"PED", tema:"Inmunidad Hepatitis B (serología)", q:"Niño de 10 años, es traído a consulta porque se desconoce si recibió la vacuna contra el virus de Hepatitis B. ¿Qué resultado confirma que el niño está protegido?", o:["IgG anti Hbc","IgM anti Hbs","IgM anti Hbe","IgM anti Hbc","IgG anti Hbs"], c:4, e:"El anti-HBs (IgG) positivo indica inmunidad, ya sea por vacunación o por infección resuelta; el anti-HBc refleja exposición al virus completo (infección natural), no protección vacunal."},
{ex:"2022-B", n:12, area:"GIN", tema:"Amenorrea secundaria (prueba de estrógeno-progesterona)", q:"Mujer de 28 años, desde hace diez meses estuvo disminuyendo su flujo menstrual hasta encontrarse en amenorrea desde hace 4 meses. Examen: emaciada; útero de seis centímetros; anexos normales. Ecografía: útero de 6 cm; anexos normales. Se le indica estrógenos y progesterona por 10 días y luego de ello, la paciente no menstrúa. ¿Dónde se encuentra la falla?", o:["Tiroides","Útero","Ovario","Hipotálamo","Hipófisis"], c:1, e:"Si tras la administración de estrógenos y progesterona no se produce sangrado de deprivación, la falla se localiza en el útero o el tracto de salida, ya que se ha descartado el hipoestrogenismo como causa al suplementar exógenamente."},
{ex:"2022-B", n:13, area:"PED", tema:"Termorregulación neonatal", q:"Cuando en la sala de partos, se coloca el paño tibio en el platillo de la balanza previo a la calibración, se evita que suceda pérdida de calor por...", o:["radiación.","conducción.","evaporación.","transpiración.","convección."], c:1, e:"El contacto directo de la piel del recién nacido con una superficie fría (la balanza) provoca pérdida de calor por conducción; el paño tibio previene este mecanismo."},
{ex:"2022-B", n:14, area:"CB", tema:"Deficiencia de riboflavina", q:"¿La deficiencia de qué vitamina ocasiona con más frecuencia la presencia de glositis y queilosis angular con ulceración y formación de costras?", o:["Rivoflavina","Vitamina A","Acido pantoténico","Acido ascórbico","Tiamina"], c:0, e:"La deficiencia de riboflavina (vitamina B2) es causa clásica de queilosis angular y glositis."},
{ex:"2022-B", n:15, area:"MED", tema:"Crisis asmática (severidad)", q:"Varón de 45 años, desde hace 2 días presenta tos, sibilantes y roncantes, luego de ingerir naproxeno se exacerba la crisis y se agrega dificultad respiratoria. Examen: PA 90/50 mmHg, FC 125X', FR 36X'; SatO2 88%; politirajes y paciente en posición sentado. ¿Cuál es la gravedad de la crisis asmática?", o:["Grave","Moderada","Casi fatal","Severa","Leve"], c:3, e:"Taquipnea marcada, taquicardia, SatO2 88% y uso intenso de músculos accesorios reflejan una crisis severa; la categoría \"casi fatal\" exigiría además tórax silente, bradicardia o alteración de conciencia, ausentes aquí."},
{ex:"2022-B", n:16, area:"GIN", tema:"Absceso tubo-ovárico", q:"Paciente de 28 años con dolor en fosa iliaca derecha y sensación de alza térmica. Examen: T° 39°C, PA 130/70 mmHg, FC 90X'. TV: tumoración en anexo derecho de 7 cm. Laboratorio: hemograma con leucocitosis y desviación izquierda. ECO TV: tumoración de 6 cm de diámetro. ¿Cuál es el tratamiento primario?", o:["Laparotomía exploratoria","Histerectomía más SOB","Clindamicina + gentamicina","Drenaje percutáneo","Drenaje transvaginal"], c:2, e:"En abscesos tuboováricos menores de 7-8 cm y en paciente hemodinámicamente estable, el manejo inicial es antibiótico endovenoso de amplio espectro (clindamicina + gentamicina u otro esquema similar), reservando el drenaje o la cirugía para la falta de respuesta."},
{ex:"2022-B", n:17, area:"PED", tema:"Desarrollo psicomotor (hitos)", q:"Según el test peruano de evaluación del desarrollo del niño. ¿A qué edad en meses el niño sentado en el suelo se para solo sin ayuda?", o:["12","9","18","15","8"], c:0, e:"El hito de pararse solo sin apoyo se ubica alrededor de los 12 meses de edad en las escalas de desarrollo psicomotor."},
{ex:"2022-B", n:18, area:"MED", tema:"Nefrotoxicidad por anfotericina B", q:"Varón de 25 años con VIH-SIDA, recibiendo tratamiento por micosis profunda; en forma brusca al cuarto día la creatinina se eleva a 2.5 mg/dl y presenta hipopotasemia; a pesar de permanecer siempre hidratado y con funciones vitales estables. ¿De los medicamentos administrados, cuál condicionó la falla renal aguda?", o:["Zidovudina","Ritonavir","Cotrimoxazol","Anfotericin B","Lamivudina"], c:3, e:"La anfotericina B es clásicamente nefrotóxica, causando lesión tubular renal con elevación de creatinina, hipokalemia e hipomagnesemia por su acción sobre los túbulos."},
{ex:"2022-B", n:19, area:"CIR", tema:"Hemotórax masivo (indicación de toracotomía)", q:"Varón de 35 años, es agredido en el tórax con objeto contundente, presentando dificultad respiratoria. Examen: PA100/50 mmHg, FC 96X', SatO2 93%. Pulmones: MV disminuido en hemitórax derecho. Rx. torax: velamiento en el 50% del HTD. Se coloca un drenaje pleural en el 5° EICD, drenando la primera hora 300cc, la segunda 250cc y la tercera 200cc de secreción hemática. ¿Cuál es la conducta a seguir?", o:["Toracotomía","Pleurectomía con decorticación","Colocación de drenaje pleural en el 2° EICD","Transfusión sanguínea","Colocación de drenaje pleural izquierdo"], c:0, e:"Un débito hemático sostenido de aproximadamente 200-300 cc/hora durante varias horas consecutivas cumple criterio de sangrado activo y es indicación de toracotomía exploratoria."},
{ex:"2022-B", n:20, area:"GIN", tema:"Náuseas y vómitos del embarazo", q:"Gestante de 8 semanas, con aversión a los alimentos de olor intenso, con náuseas y vómitos persistentes al menos 3 veces al día, sin pérdida de peso. ¿Cuál es el fármaco de elección para este caso?", o:["Ondansetrón","Prometazina","Metoclopramida","Metilprednisolona","Vitamina B6"], c:4, e:"En náuseas y vómitos leves-moderados del embarazo sin pérdida de peso, la piridoxina (vitamina B6), sola o combinada con doxilamina, es el tratamiento de primera línea recomendado."},
{ex:"2022-B", n:21, area:"PED", tema:"Atresia duodenal", q:"En un RN con radiografía simple de abdomen que muestra el signo de \"doble burbuja\". ¿Cuál es la entidad obstructiva que corresponde?", o:["Atresia duodenal","Ileo meconial","Malrotación intestinal","Duplicación intestinal","Atresia yeyunal"], c:0, e:"El signo de la doble burbuja (estómago y duodeno proximal dilatados) es patognomónico de atresia duodenal."},
{ex:"2022-B", n:22, area:"PED", tema:"Malaria", q:"Niño de 12 años, presenta anorexia, paroxismos de fiebre alta, cefalea, sudoración, mialgias y dolor abdominal. Examen: FC 100X', FR 25X', T° 39°C, palidez marcada, ictericia, hepato esplenomegalia. Laboratorio: leucocitosis, Hb 8 mg/dl, PCR 10 mg/dl, BT 10 mg/dl, BD 2 mg/dl. ¿Qué examen solicita para confirmar la sospecha diagnóstica?", o:["Gota gruesa","Hemocultivo","Elisa NS1","Rosa de Bengala","Aglutinaciones"], c:0, e:"La fiebre paroxística con hemólisis (bilirrubina indirecta elevada) y hepatoesplenomegalia orienta a malaria; la gota gruesa es el examen confirmatorio de elección."},
{ex:"2022-B", n:23, area:"PED", tema:"Mononucleosis infecciosa", q:"Niño de 5 años con fiebre de 5 días, malestar general, dolor faríngeo; visto por médico quien prescribió amoxicilina; acude a emergencia por aparición de exantema, persistencia de fiebre y dolor abdominal. Examen: erupción máculo papular generalizada; adenopatías cervicales, axilares e inguinales de 1 y 2 cm de diámetro, amígdalas hipertróficas y secreción blanquecina, esplenomegalia. ¿Cuál es el diagnóstico más probable?", o:["Mononucleosis infecciosa","Enfermedad de Kawasaki","Rubéola","Sarampión","Fiebre escarlatina"], c:0, e:"El exantema desencadenado por amoxicilina, la adenopatía generalizada, la amigdalitis exudativa y la esplenomegalia son característicos de mononucleosis infecciosa por virus de Epstein-Barr."},
{ex:"2022-B", n:24, area:"CIR", tema:"Neumotórax a tensión", q:"Varón de 25 años, sufre agresión en el lado derecho del tórax, es evaluado en emergencia por insuficiencia respiratoria e hipotensión. Examen: desviación traqueal izquierda, ausencia de ruidos respiratorios, enfisema subcutáneo en el lado derecho, distensión de las venas del cuello. ¿Cuál es el diagnóstico?", o:["Tromboembolia pulmonar","Hemoneumotórax masivo","Hemotórax","Neumotórax a tensión","Neumotórax simple"], c:3, e:"Desviación traqueal contralateral, ausencia de ruidos respiratorios e ingurgitación yugular con inestabilidad hemodinámica son el cuadro clásico de neumotórax a tensión, emergencia que requiere descompresión inmediata."},
{ex:"2022-B", n:25, area:"PED", tema:"Síndrome nefrótico (manejo de líquidos)", q:"Niña de 10 años previamente sana, peso habitual 53 Kg, presenta edema generalizado y palidez. Antecedente de haber recibido vacuna de COVID-19 15 días previos. Examen: FC 100X', FR 22 X', Peso 69 Kg, PA 70/50 mmHg. Flujo diuresis 40 cc/m2/h; proteinuria 690 mg/m2/h. Se inicia terapia con infusión de albumina y diuréticos. ¿Cuál es el volumen hídrico a indicar en el primer día de atención?", o:["Sólo el volumen de los medicamentos","Volumen según tolerancia","75% del requerimiento hídrico diario","Dos veces el requerimiento hídrico basal","50% del requerimiento hídrico diario"], c:2, e:"En el síndrome nefrótico con edema generalizado se recomienda restricción hídrica moderada (aproximadamente 75% del requerimiento basal) junto con albúmina y diuréticos, para evitar mayor sobrecarga sin comprometer la perfusión."},
{ex:"2022-B", n:26, area:"MED", tema:"Infección urinaria recidivante", q:"Mujer de 35 años acude por disuria, polaquiuria y dolor lumbar. Antecedente de ITU por E. coli hace 15 días. El nuevo urocultivo sale positivo nuevamente a E. coli. ¿Cuál es el diagnóstico de la paciente?", o:["Pielonefritis aguda","Bacteriuria asintomática","ITU recidivante","ITU complicada","ITU recurrente"], c:2, e:"La reaparición del mismo germen en un intervalo corto (días a pocas semanas) tras el tratamiento define una ITU recidivante (relapso), a diferencia de la reinfección con otro germen tras un intervalo mayor."},
{ex:"2022-B", n:27, area:"MED", tema:"Ictus isquémico (prevención secundaria)", q:"Varón de 75 años, es llevado a emergencia porque hace 3 horas presentó pérdida de la visión transitoria, disartria, hemiparesia. Examen: REG; REN; PA 140/85 mmHg, FC 78X', FR 18X'. CV: ruidos cardiacos normales; Neurológico: hemiplejía derecha. TAC cerebral sin contraste normal. ¿Cuál es el fármaco indicado como prevención secundaria?", o:["Nimodipino","Enoxaparina","Citicolina","Warfarina","Ácido acetil salicílico"], c:4, e:"En el ictus isquémico no cardioembólico, el ácido acetilsalicílico es el antiagregante de elección para prevención secundaria; la anticoagulación se reserva para fuentes cardioembólicas confirmadas."},
{ex:"2022-B", n:28, area:"CB", tema:"Músculos de la lengua", q:"Cuando se paraliza la lengua, y ésta tiene tendencia ir hacia atrás con el consecuente riesgo de asfixia. ¿Cuál es el músculo paralizado?", o:["Geniogloso","Geniohiodeo","Hipogloso","Estilogloso","Tirogloso"], c:0, e:"El músculo genioglosо protruye la lengua hacia adelante; su parálisis hace que la lengua caiga hacia atrás, con riesgo de obstrucción de la vía aérea."},
{ex:"2022-B", n:29, area:"MED", tema:"Granuloma laríngeo", q:"En el tratamiento eficaz de los granulomas laríngeos. ¿Cuál es la indicación inicial?", o:["Biopsia","Tratar causas subyacentes","Esteroides sistémico","Esteroides tópicos","Resección amplia"], c:1, e:"El tratamiento inicial de los granulomas laríngeos consiste en corregir las causas subyacentes (reflujo, abuso vocal, irritación por intubación) antes de recurrir a esteroides o cirugía."},
{ex:"2022-B", n:30, area:"PED", tema:"Galactosemia", q:"Lactante de 1 mes, que recibe lactancia materna exclusiva, presenta vómitos y diarreas desde los 4 días de vida; actualmente cursa con letargia, irritabilidad, dificultad para alimentarse, escasa ganancia de peso; llega a emergencia por presentar convulsión, ictericia, hepatomegalia, esplenomegalia. Se confirma insuficiencia hepática, tubulopatía renal y sepsis por Escherichia coli. ¿Cuál es la sospecha diagnóstica?", o:["Glucogenosis tipo II","Deficiencia de piruvato deshidrogenasa","Galactosemia","Trisomía 21","Hipotiroidismo congénito"], c:2, e:"La galactosemia clásica se manifiesta al iniciar la alimentación con lactosa (leche materna o fórmula), con falla hepática, tubulopatía renal y predisposición marcada a sepsis por E. coli."},
{ex:"2022-B", n:31, area:"SP", tema:"Políticas públicas en salud", q:"¿Qué afecta a la integralidad de las políticas públicas sociales en salud para que se consolide un programa, influenciado principalmente por la cultura organizacional?", o:["El centralismo del estado","La estrategia focalizada","La fragmentación de intervenciones","Modelos organizacionales inadecuados","Problemas de la implementación del sector"], c:3, e:"Los modelos organizacionales inadecuados, ligados a la cultura organizacional de las instituciones, son señalados como el factor que más afecta la integralidad y consolidación de los programas de salud pública."},
{ex:"2022-B", n:32, area:"MED", tema:"Intoxicación por paracetamol", q:"Se tiene un paciente que llega a la emergencia por intoxicación por paracetamol, se encontró 3 blíster abiertos al lado de su cómoda, y en emergencia tiene alterada las pruebas de función hepática. ¿Cuál es el antídoto indicado?", o:["Adrenalina","Atropina","Oxígeno","Acetilcisteína","Naloxona"], c:3, e:"La N-acetilcisteína es el antídoto específico en la intoxicación por paracetamol, repone el glutatión hepático y previene/limita la necrosis hepatocelular."},
{ex:"2022-B", n:33, area:"PED", tema:"Invaginación intestinal", q:"Lactante de 2 años, hace 6 horas presenta llanto incontenible que según refiere la madre es por dolor abdominal, que se presenta en forma periódica y se acompaña de vómitos alimentarios. Examen: se palpa masa alargada en hemiabdomen superior. Tomografía abdominal: signo de la salchicha (+). ¿Cuál es la conducta a seguir?", o:["Enema con aire","Sonda rectal","Laparotomía","Colonoscopía","Enema con bario"], c:0, e:"En la invaginación intestinal sin signos de perforación o peritonitis, la reducción no quirúrgica con enema neumático (aire) es el tratamiento de primera línea."},
{ex:"2022-B", n:34, area:"MED", tema:"Gastritis atrófica (déficit de B12)", q:"Paciente que desde hace un año presenta dolor abdominal que ocurre principalmente 3 horas después de las comidas. El dolor se atenúa con el alimento. Examen: dolor a la palpación de epigastrio. Biopsia gástrica: infiltrado inflamatorio de linfocitos y células plasmáticas con severa atrofia de la mucosa gástrica. ¿La absorción de qué vitamina se verá alterada?", o:["D","B12","E","A","C"], c:1, e:"La atrofia severa de la mucosa gástrica (gastritis atrófica) compromete a las células parietales productoras de factor intrínseco, indispensable para la absorción de vitamina B12 en el íleon terminal."},
{ex:"2022-B", n:35, area:"CIR", tema:"Lesión del nervio radial (muñeca caída)", q:"Varón de 19 años sufre asalto, acude por presentar imposibilidad para extender la muñeca derecha y los dedos por las articulaciones metacarpofalángicas. ¿Cuál es el nervio afectado?", o:["Radial","Interóseo posterior","Musculocutáneo","Cubital","Mediano"], c:0, e:"La incapacidad para extender tanto la muñeca como los dedos (muñeca caída) corresponde a lesión del nervio radial completo; una lesión aislada del interóseo posterior respeta la extensión de la muñeca."},
{ex:"2022-B", n:36, area:"MED", tema:"Enfermedad de Monge (mal de altura crónico)", q:"Varón de 47 años, nació y vive en Cerro de Pasco, refiere que desde hace 6 meses disnea progresiva, fatiga, cefalea, vértigo e insomnio. Examen: cianosis perioral, rubicundez facial y de manos, acropaquía; CV: 2do ruido cardiaco aumentado de intensidad. Laboratorio: Hb 23 g/dl, Hto 63%, SatO2 85%. ¿Cuál es el tratamiento definitivo?", o:["Sangrias","Vivir a nivel del mar","Acetazolamida","Hemodilución","Medroxiprogesterona"], c:1, e:"El descenso a nivel del mar es el tratamiento definitivo de la enfermedad de Monge (mal de altura crónico), ya que elimina el estímulo hipóxico crónico; las sangrías y la acetazolamida son medidas sintomáticas transitorias."},
{ex:"2022-B", n:37, area:"MED", tema:"Anemia ferropénica", q:"Diabético de 67 años, desde hace 3 meses se queja de fatiga, palpitaciones, mareos y dificultad para respirar. Examen: PA 110/70 mmHg, FR 18X', palidez de piel, estomatitis angular, glositis. Laboratorio: Hto 27%, Hb 8.1 g/dl, VCM 71 fl, reticulocitos 1.5%, recuento de leucocitos 6100/µl, neutrófilos 59%, recuento de plaquetas 250000/µl, hierro 29 mg/dl, capacidad total de unión al hierro 490 mg/dl, ferritina 4 ng/ml. ¿Cuál de los siguientes tipos de anemia es más probable?", o:["Talasemia","Perniciosa","Inflamación crónica","Deficiencia de hierro","Sideroblástica"], c:3, e:"Ferritina muy baja, hierro sérico bajo y capacidad total de fijación de hierro elevada, con anemia microcítica, son el perfil clásico de anemia ferropénica; en la de inflamación crónica la ferritina suele estar normal o alta."},
{ex:"2022-B", n:38, area:"SP", tema:"Funciones esenciales de salud pública", q:"¿Cuál es la función esencial en salud pública en la que se desarrolla programas sanitarios que fomenten la salud comunitaria, fortalezca la intersectorialidad, la participación social y los derechos en salud de los ciudadanos?", o:["Participación social y refuerzo","Garantía de la calidad de los servicios de salud","Desarrollo de políticas y planes","Promoción de la salud","Capacidad de gestión para organizar servicios"], c:3, e:"La función esencial de promoción de la salud incluye el fomento de la participación social, la intersectorialidad y los derechos ciudadanos en salud."},
{ex:"2022-B", n:39, area:"MED", tema:"Hiponatremia por tiazidas", q:"Varón de 78 años, hipertenso con ERC en estadio 2 acude por somnolencia. Laboratorio: Na 118 mOsm/l. ¿Qué medicamento está condicionando esta complicación?", o:["Atorvastatina","Hidroclorotiazida","Losartan","Amlodipino","Ácido acetilsalicílico"], c:1, e:"Las tiazidas son causa frecuente de hiponatremia significativa, especialmente en adultos mayores, por su efecto sobre el segmento diluyente distal de la nefrona."},
{ex:"2022-B", n:40, area:"MED", tema:"EPOC (cesación tabáquica)", q:"Varón de 60 años con diagnóstico de EPOC, presenta cuadros repetidos de tos, expectoración y disnea al ejercicio que limitan su actividad diaria. Antecedente: fumador pesado, consumo de alcohol quincenal. ¿Qué medida debe seguir el paciente para mejorar su salud?", o:["Uso de anticolinérgicos","Uso de glucocorticoides orales","Uso de glucocorticoides inhalados","Uso de broncodilatadores","Interrupción del tabaquismo"], c:4, e:"La cesación del tabaquismo es la única intervención que modifica la historia natural del EPOC, enlenteciendo el deterioro de la función pulmonar; el resto de opciones son tratamiento sintomático."},
{ex:"2022-B", n:41, area:"CB", tema:"Ciclo cardiaco", q:"¿Durante qué parte del ciclo cardíaco está abierta la válvula aórtica?", o:["Llenado ventricular rápido","Relajación ventricular isovolumétrica","Sístole auricular","Eyección ventricular disminuida","Eyección ventricular rápida"], c:4, e:"La válvula aórtica se abre al inicio de la sístole ventricular, dando paso a la fase de eyección ventricular rápida, donde ocurre la mayor parte del volumen eyectado."},
{ex:"2022-B", n:42, area:"CB", tema:"Fisiología de la lactancia", q:"¿Qué hormona produce la regularización de la eyección de la leche materna?", o:["LH","Prolactina","Progesterona","Estrógeno","Oxitocina"], c:4, e:"La oxitocina, liberada por estímulo de succión, contrae las células mioepiteliales de la glándula mamaria produciendo el reflejo de eyección láctea; la prolactina regula la producción, no la eyección."},
{ex:"2022-B", n:43, area:"MED", tema:"Tiroiditis subaguda de De Quervain", q:"Mujer de 30 años acude por fiebre, malestar general, disfagia, otalgia y aumento de volumen en el cuello. Antecedente de infección respiratoria baja hace 1 semana. Examen: PA 100/60 mmHg, FC 102X'; piel caliente; linfadenopatías cervicales dolorosas, tiroides aumentada de volumen y dolorosa. Laboratorio: leucocitosis, VSG elevado y hormonas tiroideas en valores normales. ¿Cuál es la posibilidad diagnóstica?", o:["Angina de Ludwig","Hipertiroidismo primario","Tiroiditis aguda","Adenitis tuberculosa","Nódulo tiroideo"], c:2, e:"Tiroides dolorosa tras un cuadro viral respiratorio con VSG muy elevada es característico de la tiroiditis (sub)aguda de De Quervain, de curso autolimitado."},
{ex:"2022-B", n:44, area:"CIR", tema:"Luxación de hombro (reducción)", q:"Varón de 28 años, sufre caída de una altura de 2 m. sobre su mano derecha, presentando dolor intenso en el hombro del mismo lado. Examen: asimetría anterior del hombro derecho, en rotación interna, con incapacidad funcional para movilizar el miembro superior. ¿Cuál es la posición recomendada para la reducción?", o:["Decúbito lateral","Indiferente","Supina","De pie","Prona"], c:2, e:"Para las técnicas clásicas de reducción de la luxación de hombro (tracción-contratracción, rotación externa), la posición supina del paciente es la recomendada."},
{ex:"2022-B", n:45, area:"MED", tema:"Neurotoxicidad por organofosforados", q:"Agricultor de 48 años, dedicado al cultivo desde hace 20 años, consulta por presentar desde hace 6 meses, parestesias en miembros inferiores y disminución de fuerza muscular. Examen: despierto, orientado en tiempo y persona. CV: RC normales, no soplos. Paraparesia de miembros inferiores; Lassege (-); sin nivel sensitivo. ¿Cuál es el diagnóstico más probable?", o:["Lumbociatalgia crónica","Mielitis transversa","Deficiencia de hidroxicobalamina","Neurotoxicidad retardada por órganos fosforados","Intoxicación por carbamatos"], c:3, e:"La exposición ocupacional crónica a organofosforados en agricultores puede causar una polineuropatía sensitivomotora de instauración subaguda (neurotoxicidad retardada), sin nivel sensitivo medular."},
{ex:"2022-B", n:46, area:"PED", tema:"Hernia diafragmática congénita", q:"Neonato de 2 días de vida que presenta gran dificultad respiratoria, cianosis marcada. Examen: FR 60X', FC 160X', T° 36.5°C. SatO2 90%. Tórax y Pulmones: ausencia de ruidos respiratorios en hemitórax izquierdo, abdomen excavado. ¿Cuál es el diagnóstico más probable?", o:["Secuestro pulmonar","Eventración diafragmática","Hernia diafragmática","Quiste broncogénico","Malformación adenomatoidea quística"], c:2, e:"Abdomen excavado (escafoide) por desplazamiento de vísceras abdominales al tórax, con ausencia de murmullo vesicular unilateral, es característico de la hernia diafragmática congénita."},
{ex:"2022-B", n:47, area:"CB", tema:"Síndrome de regresión caudal", q:"La ecografía reveló que el feto tenía bien desarrolladas las regiones facial y torácica, pero que las estructuras caudales eran anómalas. No tenía riñones ni vértebras lumbares y sacras; las piernas estaban fusionadas. ¿La alteración de qué proceso ha causado estas anomalías?", o:["Implantación","Trofoblasto","Gastrulación","Fecundación","Mórula"], c:2, e:"Las anomalías caudales severas (ausencia de riñones, vértebras lumbosacras, fusión de miembros inferiores) se originan por un defecto de la gastrulación, específicamente de la eminencia caudal."},
{ex:"2022-B", n:48, area:"SP", tema:"Sesgos en estudios de cohorte", q:"Un médico interesado en investigar el COVID-19 crónico en una cohorte prospectiva no cegada, cumple con los criterios de selección, randomiza su muestra calculada, y utiliza una encuesta validada. Colectó los datos para tener oportunamente los resultados y la gran mayoría de pacientes participó. Presenta un informe de avance. ¿Cuál es el sesgo más frecuente al que pueda estar expuesto el estudio?", o:["De observación","De selección","De medición","De reporte","De información"], c:4, e:"Al no estar cegado el estudio, la evaluación del desenlace mediante encuesta puede estar influida por el conocimiento de la exposición, generando sesgo de información/medición; la buena tasa de participación descarta un sesgo de selección relevante."},
{ex:"2022-B", n:49, area:"MED", tema:"Neuropatía por isoniazida", q:"Varón de 70 años es llevado a consulta por referir debilidad y parestesias. Antecedente: en tratamiento anti TB esquema I. Examen: desnutrido, estomatitis en comisura labial, ataxia, disminución en la sensibilidad vibratoria y del sentido de posición; ROT disminuidos. ¿Cuál es el fármaco relacionado con este efecto secundario?", o:["Etambutol","Pirazinamida","Rifampicina","Isoniazida","Kanamicina"], c:3, e:"La isoniazida induce depleción de piridoxina (vitamina B6) y puede causar neuropatía periférica sensitiva; se previene coadministrando piridoxina en pacientes de riesgo."},
{ex:"2022-B", n:50, area:"MED", tema:"Enfermedad de Parkinson", q:"Varón de 72 años, es llevado a la consulta por hija, quien refiere que desde hace algunos años presenta temblor en reposo, inestabilidad postural y rigidez. Examen: fascies inexpresiva, hipofonía, bradicinesia, anosmia y signo de rueda dentada. ¿Cuál es el diagnóstico más probable?", o:["Enfermedad de Wilson","Demencia vascular","Enfermedad de Parkinson","Saturninismo","Enfermedad de Alzheirmer"], c:2, e:"El tétrada clásica (temblor de reposo, rigidez en rueda dentada, bradicinesia, inestabilidad postural) más anosmia (síntoma no motor precoz) es característica de la enfermedad de Parkinson."},
{ex:"2022-B", n:51, area:"PED", tema:"Oxigenoterapia neonatal", q:"Neonato con cuadro de dificultad respiratoria se halla recibiendo FiO2 40% en casco, al ser evaluado presenta SatO2 90% y PaO2 70 mmHg. ¿Cuál es la conducta a seguir?", o:["Disminuir FiO2 a 21%","Disminuir FiO2 a 30%","Aumentar FiO2 al 100%","Aumentar FiO2 50%","Mantener FiO2 en 40%"], c:4, e:"SatO2 90% y PaO2 70 mmHg se encuentran dentro del rango aceptable para un neonato, por lo que corresponde mantener la FiO2 actual sin modificarla."},
{ex:"2022-B", n:52, area:"CIR", tema:"Trauma renal (clasificación AAST)", q:"¿A qué grado corresponde un trauma renal con desgarro mayor de 1 cm en la profundidad de la corteza renal, sin rotura del sistema colector, ni extravasación urinaria?", o:["V","IV","I","III","II"], c:3, e:"Según la clasificación AAST, un desgarro cortical mayor de 1 cm de profundidad sin compromiso del sistema colector ni extravasación urinaria corresponde a un trauma renal grado III."},
{ex:"2022-B", n:53, area:"GIN", tema:"Torsión anexial", q:"Mujer de 26 años, G0 P0, FUR hace 25 días, con sobrepeso, presenta dolor pélvico intenso repentino, náuseas y vómitos. Examen: funciones vitales estables; dolor localizado en fosa iliaca derecha; genitales: vagina sin flujo anormal; TV: útero AVF y móvil, anexo derecho doloroso y engrosado, anexo izquierdo conservado. ¿Cuál es el diagnóstico más probable?", o:["Embarazo ectópico","Apendicitis aguda","Enfermedad pélvica inflamatoria","Torsión anexial","Dolor periovulatorio"], c:3, e:"El dolor pélvico unilateral de inicio súbito e intenso, con náuseas/vómitos y anexo doloroso y engrosado al examen, es sugestivo de torsión anexial, una urgencia ginecológica."},
{ex:"2022-B", n:54, area:"MED", tema:"Crisis addisoniana", q:"Mujer de 59 años con cuadro de 2 meses caracterizado por fatiga, malestar general y pérdida de peso, luego se agrega dolor abdominal, vómitos, mareos, y sincopes. Examen: PA 80/50 mmHg, FC 100X'; pálido; presencia de hiperpigmentación. Laboratorio: hiponatremia moderada, hipoglucemia y cortisol 10 µg/100 ml luego de estimulación con ACTH. ¿Cuál sería el tratamiento a seguir?", o:["Levotiroxina","Dimenhidrinato","Cloruro sodio 3 %","Dextrosa 5%","Corticoides"], c:4, e:"La falta de respuesta del cortisol a la estimulación con ACTH confirma insuficiencia suprarrenal primaria (Addison); el tratamiento urgente y definitivo de la crisis es la reposición de corticoides (hidrocortisona)."},
{ex:"2022-B", n:55, area:"PED", tema:"Ginecomastia puberal", q:"Niño de 10 años, traído a consulta por la madre porque presenta aumento de mamas que ocasiona postura encorvado y le preocupa que el niño se aísla de sus amigos. Examen: peso 35 Kg, talla 136 cm; postura: cifosis; piel normal, adecuado TCSC, conjuntivas rosadas; tórax se evidencia telarquia bilateral; volumen testicular en 8 cc, escaso vello pubiano lacios. ¿Cuál es la información para la madre?", o:["Que es un problema transitorio llamado ginecomastia puberal","Debe hacerse controles hormonales periódicos para decidir","Que la ginecomastia en varones puede malignizarse y debe realizar biopsia","Que es un desequilibrio hormonal que requiere terapia hormonal contínua","Que debe realizarse una cirugía de urgencia"], c:0, e:"El volumen testicular de 8cc indica inicio puberal; la ginecomastia puberal es un fenómeno transitorio y benigno por el desbalance temporal entre estrógenos y andrógenos, que se resuelve espontáneamente en la mayoría de los casos."},
{ex:"2022-B", n:56, area:"SP", tema:"Tamizaje de cáncer de cuello uterino", q:"De acuerdo a las recomendaciones internacionales actuales, la toma de Papanicolaou se debe iniciar a la edad de...... años.", o:["25","17","19","15","21"], c:4, e:"Las guías clásicas de tamizaje (ACOG/USPSTF) recomiendan iniciar el Papanicolaou a los 21 años, independientemente del inicio de la actividad sexual."},
{ex:"2022-B", n:57, area:"PED", tema:"Evaluación nutricional (desnutrición aguda)", q:"¿Qué indicador antropométrico, nos permite hacer mejor el diagnóstico de desnutrición aguda en niños menores de 5 años?", o:["Pligue tricipital/E","T/E","Perímetro braquial/E","P/T","P/E"], c:3, e:"El indicador peso para la talla (P/T) es el estándar para diagnosticar desnutrición aguda (emaciación) en menores de 5 años, mientras que talla/edad refleja desnutrición crónica."},
{ex:"2022-B", n:58, area:"MED", tema:"Ictus isquémico agudo (trombolisis)", q:"Hipertenso de 54 años es traído a emergencia por presentar hemiplejia faciobraquiocrural izquierda, de una hora de evolución. Examen: PA 120/70 mmHg, FC 90X', afasia, hemiplejia izquierda, con abolición de reflejos izquierdos. Tomografía cerebral sin contraste: normal. ¿Cuál es la conducta a seguir?", o:["Administrar clopidogrel","Administrar fibrinolítico endovenoso","Solicitar angiografía cerebral","Solicitar tomografía cerebral con contraste","Anticoagulación con heparina"], c:1, e:"Dentro de la ventana terapéutica (menos de 4.5 h), sin evidencia de hemorragia en la TC sin contraste, corresponde iniciar trombólisis endovenosa si no hay contraindicaciones."},
{ex:"2022-B", n:59, area:"MED", tema:"Migraña (profilaxis)", q:"Abogada de 24 años se queja cefaleas recurrentes, desde hace 4 años. Lo refiere de tipo pulsátil, de localización frontoparietal, que suele ser muy intensa y que se intensifica con el ruido. Las crisis se presentan hasta 8 veces al mes. Examen: ansiosa, resto normal. ¿Cuál es el tratamiento farmacológico para prevenir recurrencias?", o:["Propanolol","Fluoxetina","AINEs","Ergotamina","Topiramato"], c:0, e:"Con una frecuencia de hasta 8 crisis migrañosas al mes está indicada la profilaxis; el propranolol es uno de los fármacos de primera línea clásicamente usados para prevención de migraña."},
{ex:"2022-B", n:60, area:"MED", tema:"Aneurismas cerebrales (localización)", q:"La localización más frecuente de los aneurismas cerebrales es en la arteria...", o:["cerebral media.","vertebral.","comunicante posterior.","basilar.","comunicante anterior."], c:4, e:"La arteria comunicante anterior es el sitio más frecuente de aneurismas saculares intracraneales, seguida de la comunicante posterior."},
{ex:"2022-B", n:61, area:"PED", tema:"Impétigo", q:"Niño de 2 años, presenta desde hace una semana lesiones perinasales y en ángulo labial, que están diseminándose en la parte central del rostro. Examen: lesiones pápulo vesicular perinasal, perioral y en mejillas, con borde eritematoso, algunas vesiculares con contenido purulento y otras con una costra brillante de color ámbar adheridas. ¿Cuál es el diagnóstico?", o:["Impétigo","Pénfigo vulgar","Sarna","Herpes labial","Dermatitis seborreica"], c:0, e:"Las costras color ámbar (\"melicéricas\") sobre lesiones perinasales y periorales son el signo distintivo del impétigo, habitualmente por S. aureus o S. pyogenes."},
{ex:"2022-B", n:62, area:"PED", tema:"Crup (laringotraqueítis viral)", q:"Lactante de 10 meses, presenta rinorrea, tos leve y fiebre de 2 días de evolución, en la madrugada de hoy tos \"perruna\", ronquera, estridor inspiratorio y dificultad para respirar. Examen: T° 38°C, FR 50X', FC 120X', SatO2 94%, aleteo nasal, retracciones supraesternal e intercostales, estridor contínuo y disfonía; tórax y pulmones: algunos sibilantes en ambos hemitórax. ¿En qué diagnóstico sospecha?", o:["Crup","Cuerpo extraño","Absceso retrofaríngeo","Angioedema","Bronquiolitis"], c:0, e:"Tos perruna, disfonía y estridor inspiratorio tras un pródromo catarral son el cuadro clásico del crup (laringotraqueítis viral), típicamente por parainfluenza."},
{ex:"2022-B", n:63, area:"CIR", tema:"Complicaciones de la traqueostomía", q:"¿Cuál es una complicación de la traqueostomía?", o:["Hemotórax","Estenosis traqueal","Absceso faríngeo","Disfunción cuerdas vocales","Estenosis subglótica"], c:1, e:"La estenosis traqueal a nivel del estoma es una complicación tardía reconocida de la traqueostomía, por fibrosis cicatricial de la vía aérea."},
{ex:"2022-B", n:64, area:"PED", tema:"Vacuna SPR (efectos adversos)", q:"Luego de la aplicación de la vacuna SPR. ¿Después de cuántos días usualmente se observan posibles efectos postvacunales?", o:["15 y 18","4 y 6","7 y 14","19 y 21","1 y 3"], c:2, e:"Los efectos postvacunales de la SPR (fiebre, exantema) por ser una vacuna de virus vivos atenuados aparecen típicamente entre el 7.º y 14.º día, tiempo que toma la replicación viral."},
{ex:"2022-B", n:65, area:"MED", tema:"Hiperkalemia (ECG)", q:"Mujer de 60 años diabética sin control regular es llevada a emergencia por cursar con debilidad muscular. Examen: disminución de fuerza muscular en miembros inferiores. EKG: ondas T picudas, prolongación del intervalo PR y ensanchamiento del complejo QRS. ¿Cuál es el trastorno electrolítico relacionado con dichos hallazgos?", o:["Hiponatremia","Hipofosfatemia","Hipernatremia","Hiperkalemia","Hipercalcemia"], c:3, e:"Ondas T picudas seguidas de prolongación del PR y ensanchamiento del QRS son la progresión electrocardiográfica clásica de la hiperkalemia."},
{ex:"2022-B", n:66, area:"PED", tema:"Salmonelosis (diarrea invasiva)", q:"Niña de 3 años de edad, desde hace 3 días presenta fiebre, dolor abdominal periumbilical tipo cólico, vómitos y deposiciones semilíquidas sanguinolentas y con moco. Madre cría aves de corral. ¿Cuál es el probable agente etiológico?", o:["Adenovirus","Campylobacter","Giardia","E. coli","Salmonella"], c:4, e:"El antecedente de crianza de aves de corral es la asociación clásica con Salmonella, causa frecuente de diarrea invasiva (disentería) en niños."},
{ex:"2022-B", n:67, area:"MED", tema:"Meningitis bacteriana", q:"Varón de 72 años, presenta cefalea, fiebre y desorientación desde hace 2 días. Examen: destaca rigidez de nuca marcada. Fondo de ojo: no hipertensión endocraneana. Laboratorio: LCR turbio, con proteínas 120 mg/dl, glucosa de 27 mg/dl y leucocitos 1800/µl, con 90% de polimorfonucleares. ¿Cuál es la etiología más probable?", o:["Tuberculosis","Bacteriana","Herpética","Micotica","Neoplásica"], c:1, e:"Inicio agudo (2 días), LCR turbio con predominio de polimorfonucleares, hipoglucorraquia marcada e hiperproteinorraquia son característicos de meningitis bacteriana."},
{ex:"2022-B", n:68, area:"CB", tema:"Enfermedad de Parkinson (fisiopatología)", q:"Varón de 60 años, diabético e hipertenso; nota temblor de manos en reposo, pero con rigidez de músculos, así como dificultad para deambular, lentitud de pensamiento y dificultad para el habla. ¿Qué hormona está implicada en la presente patología?", o:["Noradrenalina","Adrenalina","Acetilcolina","Dopamina","Glucagón"], c:3, e:"El síndrome parkinsoniano se debe a la degeneración de neuronas dopaminérgicas de la sustancia negra, con el consiguiente déficit de dopamina."},
{ex:"2022-B", n:69, area:"MED", tema:"Depresión mayor", q:"Mujer de 40 años, desde hace 3 semanas, siente tristeza y deseos de llorar, pérdida de interés por el trabajo, insomnio, cansancio persistente y dificultad para concentrarse en las actividades que realiza. ¿Cuál es el diagnóstico más probable?", o:["Obsesiva","Estrés situacional","Fobia social","Depresión mayor","Episodio maniaco"], c:3, e:"Ánimo depresivo y anhedonia de más de 2 semanas, junto con insomnio, fatiga y dificultad de concentración, cumplen criterios de episodio depresivo mayor."},
{ex:"2022-B", n:70, area:"MED", tema:"Rabdomiólisis por ejercicio", q:"Varón de 20 años, ingresa por presentar intenso dolor muscular, debilidad, náuseas, vómitos y orina color marrón rojiza. El día anterior participó en maratón de 15 Km. Examen: PA 120/80 mmHg, FC 86 X´, FR 18 X´, T° 38°C. Polimialgia, paraparesia. Laboratorio: Hto 49%, úrea 70 mg/dl, creatinina 7 mg/dl, CPK 2400 U/l, TGO 160 U/l, TGP 138 U/l, Na 142 mMol/l; K 5.8 mMol/l. ¿Cuál es el diagnóstico más probable?", o:["Desequilibrio hidroelectrolítico","Parálisis kalémica","Hiperkalemia","Golpe de calor","Rabdomiolisis"], c:4, e:"Ejercicio extenuante, mialgias, orina oscura (mioglobinuria), CPK muy elevada e insuficiencia renal aguda con hiperkalemia secundaria son el cuadro característico de rabdomiólisis de esfuerzo."},
{ex:"2022-B", n:71, area:"MED", tema:"Endocarditis infecciosa", q:"Varón de18 años, drogadicto; hace 1 semana presenta fiebre, astenia, anorexia, lumbago, poliartralgias. Examen: PA 100/50 mmHg, FC 110X', T° 40°C; petequias y hemorragias subungueales, nódulo eritematoso y doloroso en el pulpejo de dedo. CV: soplo diastólico en foco aórtico. Laboratorio: leucocitosis con desviación izquierda; VSG 40 mm/h; Orina: leucocitos 10-16 x campo, hematíes 22-30 x campo (crenados), PCR 15 mg/dl. ¿Cuál es el probable diagnóstico?", o:["Lupus eritematoso sistémico","Mixoma auricular","Endocarditis infecciosa","Fiebre reumática","Glomerulonefritis mesangial"], c:2, e:"Usuario de drogas endovenosas con fiebre, nuevo soplo, nódulos de Osler (pulpejo doloroso), hemorragias en astilla y hematuria por glomerulonefritis por inmunocomplejos configuran endocarditis infecciosa."},
{ex:"2022-B", n:72, area:"GIN", tema:"Endometriosis", q:"Paciente de 34 años, G0 P0, MAC (-), RC 3/30, casada hace 4 años, acude por dispareunia y leve dismenorrea. Examen: funciones vitales normales; espéculoscopía: no flujo vaginal, cérvix lateralizado, sin lesiones. TV: útero de 8 cm, en retroversión fija. Tacto rectal: se palpa nodularidad y sensibilidad en área uterosacra. ¿Cuál es el diagnóstico más probable?", o:["Endometriosis","Adenomiosis","Miomatosis","Enfermedad pélvica inflamatoria","Síndrome de congestión pelviana"], c:0, e:"Nodularidad dolorosa en ligamentos uterosacros, retroversión uterina fija, dispareunia e infertilidad son hallazgos clásicos de endometriosis."},
{ex:"2022-B", n:73, area:"MED", tema:"Gasometría (acidosis respiratoria)", q:"Varón de 68 años que ha fumado tres paquetes de cigarrillos al día durante 40 años; ingresa con febrícula, disnea y sibilancias. Examen: cianosis y tórax en barril. Laboratorio: AGA: pH 7.29, PCO2 70 mmHg, PO2 54 mmHg, HCO3 33 mEq/l, Na 139 mEq/l, Cl 95 mEq/l. ¿Cuál es la interpretación?", o:["Alcalosis metabólica","Acidosis metabólica","Acidosis respiratoria","Acidosis mixta","Alcalosis respiratoria"], c:2, e:"El PCO2 muy elevado con acidemia y el HCO3 alto como respuesta compensadora renal (crónica) definen una acidosis respiratoria, propia de la retención crónica de CO2 en el EPOC reagudizado."},
{ex:"2022-B", n:74, area:"PED", tema:"Tos ferina", q:"Lactante de 10 meses, desde hace 7 días presenta rinorrea, tos seca y fiebre; hace 2 días tos exigente que ocasiona rubicundez facial y vómitos lácteos. Antecedente: vacunas hasta los 2 meses. Examen: FR 24X', FC 120X', T° 36,5°C, SatO2 96%; al examinarlo con bajalenguas se desencadena tos en salvas y cianosis. Laboratorio: leucocitos 18000/µl. ¿Cuál es el diagnóstico probable?", o:["Laringotraqueitis","Epiglotitis","Neumonía","Bronquiolitis","Tos ferina"], c:4, e:"Esquema de vacunación incompleto, tos paroxística con cianosis y vómito postusivo son característicos de tos ferina (Bordetella pertussis)."},
{ex:"2022-B", n:75, area:"MED", tema:"Intoxicación por organofosforados (tratamiento)", q:"Mujer de 25 años, es llevada a emergencia por haber sido encontrada en su habitación con abundante secreción salival y sibilantes luego de una discusión familiar. Examen: PA 100/60 mmHg, FC 45X'; diaforesis, sialorrea, miosis; sibilantes inspiratorios; relajación de esfínteres. Se indica tratamiento médico correspondiente. Luego de 5 horas la paciente presenta xerostomía y midriasis. ¿Qué medicamento recibió en emergencia la paciente?", o:["Atropina","Neostigmina","Pilocarpina","Nicotina","Edrofonio"], c:0, e:"El cuadro colinérgico (miosis, sialorrea, bradicardia, broncorrea) sugiere intoxicación por organofosforados; la aparición posterior de xerostomía y midriasis (signos anticolinérgicos) confirma que se administró atropina como antídoto."},
{ex:"2022-B", n:76, area:"MED", tema:"Trombosis venosa profunda", q:"Mujer de 50 años, luego de viaje prolongado, presenta súbitamente, dolor en la pierna derecha y dificultad para la marcha. Examen de miembros inferiores: aumento de volumen, calor, distensión venosa y signo de Homan (+). ¿Cuál es el diagnostico probable?", o:["Insuficiencia arterial aguda","Trombosis venosa profunda","Celulitis","Varices de miembros inferiores","Trombosis arterial"], c:1, e:"El antecedente de inmovilización prolongada (viaje) con edema unilateral, calor y signo de Homan positivo es característico de trombosis venosa profunda."},
{ex:"2022-B", n:77, area:"MED", tema:"Ototoxicidad por antibióticos tópicos", q:"Mujer de 35 años que cursa hace 2 semanas con otitis media, lleva tratamiento antibiótico tópico y antiinflamatorios vía oral. Presenta desde hace 1 día sordera. ¿Qué espera encontrar en la audiometría?", o:["Hipoacusisa mixta","Hipoacusia inducida por ruido","Trauma acústico","Hipoacusia neurosensorial","Hipoacusia de conducción"], c:3, e:"El uso de antibióticos tópicos ototóxicos (p. ej. aminoglucósidos) en presencia de perforación timpánica por la otitis media puede alcanzar el oído interno y producir hipoacusia neurosensorial."},
{ex:"2022-B", n:78, area:"MED", tema:"Hipertensión renovascular", q:"Mujer de 55 años, consulta por malestar general y disminución de volumen urinario. Examen: PA 150/115 mmHg y soplo abdominal. En estudio angiográfico se evidencia estenosis del 80% de arteria renal izquierda. ¿Qué hormona esperaría encontrar incrementada?", o:["FGF-23","Leptina","Calcitonina","Renina","Tiroxina"], c:3, e:"La hipoperfusión renal por estenosis de la arteria renal activa el sistema renina-angiotensina-aldosterona, elevando la renina plasmática (hipertensión renovascular)."},
{ex:"2022-B", n:79, area:"MED", tema:"Anorexia nerviosa", q:"Adolescente de 15 años, presenta mareo y desvanecimiento los últimos días; refiere hiporexia, baja de peso, estreñimiento y uso de laxantes. Examen: T° 36°C, FC 72X', FR 16X'; Peso 30 Kg; ansiosa, adelgazada, pálida, piel seca, crecimiento del vello facial, alopecia en zona parietal; arritmia cardiaca; abdomen escafoide; acrocianosis y llenado capilar lento. ¿Cuál es el diagnóstico probable?", o:["Síndrome ansioso","Bulimia","Diabetes juvenil","Anorexia nerviosa","Hipertiroidismo"], c:3, e:"Restricción alimentaria con pérdida de peso severa, lanugo (vello facial), bradicardia/arritmia, hipotermia y uso de laxantes conforman el cuadro clásico de anorexia nerviosa con signos de inestabilidad médica."},
{ex:"2022-B", n:80, area:"MED", tema:"Glaucoma agudo de ángulo cerrado (tratamiento)", q:"El tratamiento de inicio del glaucoma agudo de ángulo cerrado es...", o:["trabeculotomía.","iridotomía periférica.","acetazolamida.","prednisolona.","brimonidina."], c:2, e:"El tratamiento médico inicial busca bajar rápidamente la presión intraocular con acetazolamida sistémica (más hipotensores tópicos); la iridotomía periférica con láser es el tratamiento definitivo posterior."},
{ex:"2022-B", n:81, area:"MED", tema:"Sífilis primaria", q:"Mujer de 23 años consulta porque hace 1 semana tuvo \"bultitos\" indoloros en ambas ingles y ahora presenta lesión vulvar. Examen: en labio mayor derecho se observa lesión ulcerada única, de bordes evertidos, no dolorosa. ¿Cuál es el diagnóstico más probable?", o:["Condilomatosis ulcerada","Sífilis primaria","Herpes genital","Chancroide","Donovanosis"], c:1, e:"Úlcera genital única, indolora, de bordes evertidos (chancro), con adenopatía inguinal indolora, es el cuadro clásico de sífilis primaria; el chancroide, en contraste, produce úlceras dolorosas con adenopatía dolorosa."},
{ex:"2022-B", n:82, area:"GIN", tema:"Isoinmunización Rh (anemia fetal)", q:"El aumento en el gasto cardíaco y la disminución de la viscosidad de la sangre que se puede producir en un feto de madre Rh (-) nos obliga a descartar la presencia de...", o:["trisomía 21.","infección por parvovirus B19.","malformación adenomatosa quística fetal.","arritmia fetal.","anemia fetal."], c:4, e:"En la isoinmunización Rh, la hemólisis fetal produce anemia, que a su vez aumenta el gasto cardiaco y disminuye la viscosidad sanguínea; esto se evalúa mediante el pico sistólico de la arteria cerebral media."},
{ex:"2022-B", n:83, area:"GIN", tema:"Síndrome genitourinario de la menopausia", q:"Paciente de 54 años, refiere disuria, niega otras molestias, presentó su última regla hace dos años. Examen: vagina pálida, útero de 6 cm. Urocultivo negativo. ¿Cuál es el tratamiento a seguir?", o:["Progesterona oral","Estrógenos orales","Estriol tópico","Estrógenos con progesterona orales","Lubricantes vaginales"], c:2, e:"La disuria sin infección en una mujer posmenopáusica con atrofia vaginal corresponde al síndrome genitourinario de la menopausia; el estrógeno tópico (estriol) es de primera elección por su eficacia local y bajo riesgo sistémico."},
{ex:"2022-B", n:84, area:"CIR", tema:"Fractura orbitaria (blowout)", q:"Varón de 17 años con visión doble luego de trauma orbitario. Examen: enoftalmos con restricción del movimiento ocular hacia arriba, asociado a dolor en ojo izquierdo; ojo derecho normal. ¿Cuál es el probable diagnóstico?", o:["Fractura del piso de orbita","Perforación de la córnea","Ruptura del globo ocular","Parálisis del III par","Parálisis del IV par"], c:0, e:"El atrapamiento del músculo recto inferior en una fractura del piso orbitario (blowout) produce restricción de la mirada hacia arriba, diplopía y enoftalmos."},
{ex:"2022-B", n:85, area:"GIN", tema:"Infertilidad (evaluación inicial)", q:"Paciente de 28 años que está buscando tener familia desde hace seis meses, sin alteraciones menstruales ni antecedentes de importancia, su pareja de 34 años tiene un hijo de compromiso previo. ¿Cuál es el manejo a seguir?", o:["Asesoría y observación","Histerosalpingografía","Dosaje hormonal","Ecografía transvaginal","Espermatograma"], c:0, e:"Con solo 6 meses de búsqueda, ciclos regulares y sin factores de riesgo (la fertilidad previa de la pareja no descarta un factor femenino ni obliga a estudio inmediato), corresponde asesoría y observación antes de iniciar estudios de infertilidad, que se indican tras 12 meses sin lograr embarazo."},
{ex:"2022-B", n:86, area:"PED", tema:"Reanimación neonatal (algoritmo NRP)", q:"Después de realizar las primeras medidas de reanimación a un neonato que se halla en apnea, inicia ventilación a presión positiva con bolsa y máscara con FiO2 21% con adecuada expansión toráxica, luego de 15 segundos el ayudante le informa que la frecuencia cardiaca va en aumento y la SatO2 90%, aunque continúa en apnea. ¿Cuál es la conducta a seguir?", o:["Iniciar masaje cardíaco","Aumentar la FiO2 al 30%","Aumentar la FiO2 al 100%","Indicar ventilación mecánica","Mantener FiO2 al 21% por 30 segundos más"], c:4, e:"El aumento de la frecuencia cardiaca confirma que la ventilación a presión positiva es efectiva; no se requiere masaje cardiaco ni escalar la FiO2, se debe continuar la PPV con la FiO2 actual y reevaluar."},
{ex:"2022-B", n:87, area:"GIN", tema:"Prolapso de cordón umbilical", q:"Gran multigesta de 36 semanas, con polihidramnios leve y presentación alta; se encuentra en trabajo de parto con monitoreo electrónico, buena progresión hasta el momento y dilatación de 6 cm. La paciente \"rompe bolsas\"; y se evidencia líquido amniótico claro; luego, se objetiva bradicardia fetal súbita y persistente. ¿Cuál es el diagnóstico más probable?", o:["Sufrimiento fetal agudo","Abruptio placentae","Prolapso de cordón","Infección intrauterina","Ruptura uterina"], c:2, e:"Presentación alta y polihidramnios son factores de riesgo clásicos de prolapso de cordón; la bradicardia fetal súbita inmediatamente tras la rotura de membranas es el signo de alarma característico."},
{ex:"2022-B", n:88, area:"MED", tema:"Absceso periamigdalino", q:"Mujer de 34 años, hace 4 días presenta odinofagia que se acompaña de alza térmica; hace 24 horas con dificultad para abrir la boca. Examen: FC 100X',T° 38.5°C; presencia de flogosis en región del velo del paladar con desviación de la úvula, con aumento de volumen del pilar anterior. ¿Cuál es el probable diagnóstico?", o:["Absceso periamigdaliano","Gingivitis","Adenoiditis aguda","Angina de Ludwig","Amigdalitis aguda"], c:0, e:"Trismus, desviación de la úvula y abombamiento asimétrico del pilar amigdalino anterior son el cuadro clásico del absceso periamigdalino."},
{ex:"2022-B", n:89, area:"GIN", tema:"Prolapso de órganos pélvicos (POP-Q)", q:"Paciente de 62 años, refiere sensación de bulto en vagina hace 4 años que ha ido aumentando progresivamente y se asocia a disconfort de la zona genital. Examen: la porción más distal del prolapso está a menos de 1 cm distal del plano del himen. Según POP-Q. ¿A qué estadío corresponde esta distopia genital?", o:["I","0","IV","III","II"], c:4, e:"Según el sistema POP-Q, el estadío II corresponde a un punto de mayor prolapso ubicado entre -1 cm y +1 cm respecto al plano del himen."},
{ex:"2022-B", n:90, area:"GIN", tema:"Síndrome de congestión pélvica", q:"Paciente G0P0, sin pareja hace 2 años, con menstruaciones regulares, refiriere dolor pélvico crónico bilateral y lumbalgia de moderada intensidad. TV: útero levemente doloroso a la palpación, anexos leve dolor. Ecografía: imágenes tubulares anecoicas, tortuosas, con diámetro mayor de 4 mm. Doppler: flujo de baja velocidad tanto a nivel periuterino como de anexos. ¿Cuál es el diagnóstico más probable?", o:["Hidrosálpinx bilateral","EPI estadío 2","Síndrome de congestión pelviana","Ovarios poliquísticos","Endometriosis"], c:2, e:"Estructuras tubulares anecoicas y tortuosas (venas dilatadas) con flujo de baja velocidad peri-uterino y anexial son característicos del síndrome de congestión pélvica por varices pélvicas."},
{ex:"2022-B", n:91, area:"MED", tema:"Anemia ferropénica (respuesta al tratamiento)", q:"¿Qué resultado de laboratorio evidencia tempranamente respuesta al tratamiento con hierro en la anemia ferropénica?", o:["Transferrina","Albúmina","Ferritina","Hemoglobina","Reticulocitosis"], c:4, e:"La reticulocitosis aparece a los 5-10 días de iniciado el hierro, siendo el primer marcador de respuesta, antes de que se normalicen la hemoglobina o la ferritina."},
{ex:"2022-B", n:92, area:"CB", tema:"Vía óptica", q:"¿La lesión de qué estructura anatómica podría provocar una ceguera total del ojo derecho?", o:["Tracto óptico derecho","Tracto óptico izquierdo","Nervio óptico derecho","Nervio óptico izquierdo","Quiasma óptico"], c:2, e:"Solo una lesión del nervio óptico derecho (antes del quiasma) puede producir ceguera completa y aislada del ojo derecho; las lesiones retroquiasmáticas producen defectos de campo bilaterales, no ceguera monocular total."},
{ex:"2022-B", n:93, area:"SP", tema:"Determinantes de la salud (modelo de Lalonde)", q:"¿Cuál es el determinante que es fundamental y se brinda un peso importante dentro del proceso de la salud enfermedad, según Lalonde?", o:["Biología humana","Organización de servicios de salud","Social","Estilo de vida","Ambiente"], c:3, e:"En el modelo de Lalonde, el estilo de vida es el determinante al que se le atribuye el mayor peso relativo sobre el proceso salud-enfermedad, por encima de la biología, el ambiente y los servicios de salud."},
{ex:"2022-B", n:94, area:"MED", tema:"Primera crisis convulsiva (evaluación)", q:"Varón 18 años, sin antecedentes importantes, es traído a Emergencia por los bomberos por haber presentado convulsiones generalizadas en su trabajo hace 30 minutos, con pérdida de conciencia y micción espontánea. Examen: desorientado en tiempo y espacio, pupilas fotoreactivas, no rigidez de nuca. ¿Qué examen se debe solicitar de inmediato para precisar el diagnóstico?", o:["Tomografía cerebral","Determinación de opiáceos en sangre","Arteriografía cerebral","Punción lumbar","Electroencefalograma"], c:0, e:"Ante una primera crisis convulsiva generalizada en un adulto, la tomografía cerebral es el estudio inicial urgente para descartar una lesión estructural causante."},
{ex:"2022-B", n:95, area:"GIN", tema:"Anticoncepción en adolescentes", q:"Acude al consultorio del adolescente, una paciente de dieciséis años solicitando un método de planificación familiar, refiere tener una relación sexual cada quince días y pareja estable. ¿Cuál es el método recomendado?", o:["Píldora de emergencia","Anticonceptivos parenterales trimestrales","Anticonceptivos orales combinados","Anticonceptivos parenterales mensuales","Preservativos"], c:2, e:"En una adolescente con pareja estable que busca anticoncepción regular y reversible, los anticonceptivos orales combinados son una opción de primera línea recomendada, sin contraindicaciones evidentes; debe reforzarse además el uso de preservativo como doble protección frente a ITS."},
{ex:"2022-B", n:96, area:"PED", tema:"Hipoglucemia neonatal sintomática", q:"Neonato a término, pequeño para edad gestacional; peso 2,500 g; presenta succión débil, letargia y tremor. Se realiza hemoglucotest cuyo resultado es de 24 mg/dl. ¿Cuál es la actitud terapéutica?", o:["Colocar sonda orogástrica y administrar dextrosa al 5% 5 cc","Dextrosa al 10% manteniendo un VIG de 6-8 mg/Kg/min","Ofertar leche materna con mayor frecuencia","Realizar nuevo dosaje a las dos horas para confirmar el diagnóstico","Dextrosa 10% 5 cc IV en bolo luego mantener un VIG de 6-8 mg/Kg/min"], c:4, e:"En hipoglicemia neonatal sintomática (letargia, tremor, succión débil) se requiere un bolo endovenoso de dextrosa al 10% seguido de infusión continua a una velocidad de infusión de glucosa (VIG) de 6-8 mg/kg/min."},
{ex:"2022-B", n:97, area:"CIR", tema:"Anestesia raquídea (nivel de punción)", q:"¿Cuál es el nivel de inyección de preferencia en la anestesia raquídea?", o:["Debajo L3-L4","No hay preferencia","Debajo L4-L5","Siempre debajo L4","Debajo de L1-L2"], c:0, e:"El espacio L3-L4 (a la altura de las crestas ilíacas, línea de Tuffier) es el nivel preferido para la punción raquídea en adultos, por debajo de la terminación habitual de la médula espinal (L1-L2), minimizando el riesgo de lesión neurológica."},
{ex:"2022-B", n:98, area:"GIN", tema:"Fiebre posoperatoria (las 5 W)", q:"Paciente en su segundo día posoperada de una cesárea, con presencia de fiebre de 38.5 °C. Examen: mamas normales, abdomen blando depresible no doloroso, útero a tres centímetros por debajo de cicatriz umbilical, herida operatoria bien afrontada, loquios sin mal olor. De acuerdo al día posoperatorio. ¿Cuál sería su primera presunción diagnóstica?", o:["Infección de herida operatoria","Mastitis","Endometritis","Atelectasia pulmonar","Infección del tracto urinario"], c:3, e:"Sin hallazgos que sugieran endometritis, infección de herida o mastitis, y en el segundo día posoperatorio, la causa más frecuente de fiebre (regla nemotécnica de las \"5 W\") es la atelectasia pulmonar."},
{ex:"2022-B", n:99, area:"MED", tema:"Fobia específica", q:"Mujer de 28 años, que presenta un temor acusado y persistente, excesivo o irracional, desencadenado por la presencia de sangre. ¿Qué tipo de trastorno presenta?", o:["Fobia","Obsesivo compulsivo","Dismórfico corporal","Apego reactivo","De acumulación"], c:0, e:"El temor excesivo e irracional desencadenado por un estímulo específico (la sangre) define una fobia específica (tipo sangre-inyección-herida)."},
{ex:"2022-B", n:100, area:"MED", tema:"Amebiasis intestinal", q:"Varón de 35 años, presenta hace 15 días dolor abdominal intenso en cuadrantes inferiores; diarrea disentérica 10-12 cámaras al día; malestar general, no fiebre. ¿Cuál es el agente etiológico más probable?", o:["Staphyloccocus aureus","Campylobacter","E. Coli enteropatógena","Entamoeba histolytica","Salmonella enteridis"], c:3, e:"Disentería de curso subagudo/crónico (15 días) sin fiebre significativa es más típica de amebiasis intestinal (Entamoeba histolytica) que de las disenterías bacterianas, que suelen ser más agudas y febriles."},
];
